    if (CollectionUtils.isNotEmpty(errorUsers)) {
        log.error("registerUsersError:{}", JSONUtil.toJsonStr(errorUsers));
        throw new BusinessException(String.join(",", errorUsers) + "添加失败");
    }

    return result;

}


private List<UserRegisterVo> registerUsersIn(UsersCreateRo ro) {

    List<UserRegisterVo> result=new ArrayList<>();

    Long operatorId = SessionContext.getUserId();

    List<UserRegisterRo> users = ro.getUsers();
    List<String> reqEmails = users.stream().map(UserRegisterRo::getEmail).toList();

    //已存在
    List<UserRegisterRo> addUsers = new ArrayList<>();
    List<UserRegisterRo> recoverUsers = new ArrayList<>();
    List<UserSimpleInfoVo> userByEmails = apitableGrpcClientService.getUserByEmails(reqEmails);
    Map<String, UserSimpleInfoVo> userByEmailsMap = new HashMap<>();
    if(CollectionUtils.isNotEmpty(userByEmails)){
        List<String> existAll = userByEmails.stream().map(UserSimpleInfoVo::getEmail).toList();
        userByEmailsMap = userByEmails.stream().collect(Collectors.toMap(UserSimpleInfoVo::getEmail, Function.identity()));
        addUsers= users.stream().filter(x->!existAll.contains(x.getEmail())).toList();

        List<String> existNormal = userByEmails.stream().filter(x -> x.getStatus() == 0).map(UserSimpleInfoVo::getEmail).toList();
        if(CollectionUtils.isNotEmpty(existNormal)){
            existNormal.forEach(x->{
                result.add(new UserRegisterVo(x, RegisterResultType.FAIL.getId(),"用户已存在"));
            });
        }

        List<String> existDisable = userByEmails.stream().filter(x -> x.getStatus() == 1).map(UserSimpleInfoVo::getEmail).toList();
        if(CollectionUtils.isNotEmpty(existDisable)){
            recoverUsers= users.stream().filter(x->existDisable.contains(x.getEmail())).toList();
        }

    }else{
        addUsers=users;
    }

    //expat小组
    Set<String> contractorUserEmails = new HashSet<>();
    List<MattermostGroupResp> usersWithTeam = getUsersWithTeam(mattermostProperties.getMmXTeamId());
    List<MattermostGroupResp> contractorTeam =
            usersWithTeam.stream().filter(t -> t.getDisplaygroupname().toLowerCase().startsWith("expat")).toList();
    if(CollectionUtils.isNotEmpty(contractorTeam)){
        contractorTeam.forEach(ct->{
            List<MattermostGroupResp.UserSimpleResp> expatUsers = ct.getUsers();
            if(CollectionUtils.isNotEmpty(expatUsers)){
                expatUsers.forEach(user-> contractorUserEmails.add(user.getEmail()));
            }
        });
    }


    //新建
    List<Long> newUserIds = new ArrayList<>();
    if(CollectionUtils.isNotEmpty(addUsers)){
        addUsers.forEach(u -> {
            try {
                Long userId = apitableGrpcClientService.register(u.getEmail(), u.getNickName(),false);
                affineHttpClientService.createUser(
                        CreateUserRequest.builder().email(u.getEmail()).userName(u.getNickName()).password("123456").build(),operatorId);
                if (null != userId){
                    newUserIds.add(userId);
                    Integer registerResult = RegisterResultType.SUCCESS.getId();
                    if(contractorUserEmails.contains(u.getEmail())){
                        registerResult =  RegisterResultType.SUCCESS_FROM_EXPAT.getId();
                    }
                    result.add(new UserRegisterVo(u,userId, registerResult,null));
                } else {
                    result.add(new UserRegisterVo(u.getEmail(),RegisterResultType.FAIL.getId(),"用户添加失败"));
                }
            } catch (Exception e) {
                result.add(new UserRegisterVo(u.getEmail(),RegisterResultType.FAIL.getId(),"用户添加失败"));
            }
        });
    }

    //恢复
    if(CollectionUtils.isNotEmpty(recoverUsers)){
        for (UserRegisterRo u : recoverUsers) {
            try {
                apitableGrpcClientService.recoverUserByEmail(u.getEmail(), false);
                affineHttpClientService.createUser(
                        CreateUserRequest.builder().email(u.getEmail()).userName(u.getNickName()).password("123456").build(), operatorId);
                UserSimpleInfoVo recoverUserInfo = userByEmailsMap.get(u.getEmail());
                newUserIds.add(recoverUserInfo.getId());
                Integer registerResult = RegisterResultType.SUCCESS_FROM_DISABLE.getId();
                if(contractorUserEmails.contains(u.getEmail())){
                    registerResult =  RegisterResultType.SUCCESS_FROM_EXPAT.getId();
                }
                result.add(new UserRegisterVo(u,recoverUserInfo.getId(), registerResult,null));

