30→  if (checkMsg.length > 0) {
31→    const canConfirm = !checkResult.some((it) => it.checkResult === AddUserCheckResult.EXISTS);
32→    const confirm = await antdApp.modal.confirm({
33→      title: t('managementAddUserCheckTitle'),
34→      width: 480,
35→      icon: null,
