import { addProjectUsersAPI, AddUserCheckResult, checkRegisterUsers } from '@/common/api/project';
import { antdApp } from '@/common/pageInit';
import { t } from '@/i18n';
import type { IProjectUser } from '@/types/user';

export async function addUserWithCheck(users: IProjectUser[], teamIds: string[]) {
  const checkResult = await checkRegisterUsers({
    users: users.map((o) => ({
      nickName: o.nickName, email: o.email.includes('@yottastudios.com') ? o.email : `${o.email}@yottastudios.com`,
    })),
    teamIds,
  });
  const checkMsg: React.ReactNode[] = [];
  for (const resultItem of checkResult) {
    switch (resultItem.checkResult) {
      case AddUserCheckResult.EXISTS: {
        checkMsg.push(<div key={resultItem.email} style={{ color: 'var(--color-error)' }}>{t('managementAddUserCheckMsgExists', { email: resultItem.email })}</div>);
        break;
      }
      case AddUserCheckResult.DISABLED_USER: {
        checkMsg.push(<div key={resultItem.email}>{t('managementAddUserCheckMsgDisabled', { email: resultItem.email })}</div>);
        break;
      }
      case AddUserCheckResult.EXPAT_USER: {
        checkMsg.push(<div key={resultItem.email}>{t('managementAddUserCheckMsgExpat', { email: resultItem.email })}</div>);
        break;
      }
    }
  }
  if (checkMsg.length > 0) {
    const canConfirm = !checkResult.some((it) => it.checkResult === AddUserCheckResult.EXISTS);
    const confirm = await antdApp.modal.confirm({
      title: t('managementAddUserCheckTitle'),
      width: 480,
      icon: null,
      content: (
        <>
          {checkMsg}
          {canConfirm && t('managementAddUserCheckConfirm')}
        </>
      ),
      footer: (_originNode, { OkBtn, CancelBtn }) => {
        return (
          <>
            <CancelBtn />
            {canConfirm && <OkBtn />}
          </>
        );
      },
    });
    if (!confirm) return false;
  }
  const result = await addProjectUsersAPI(users, teamIds);
  return result;
}

