public List<UserRegisterCheckVo> checkRegisterUsers(UsersCreateRo ro) {

    boolean internalNetwork = constProperties.isInternalNetwork();
    if(internalNetwork || mmTestOnlyOnlyTag){
        return checkRegisterUsersIn(ro);
    }else{
        return checkRegisterUsersEx(ro);
    }
}

private List<UserRegisterCheckVo> checkRegisterUsersEx(UsersCreateRo ro) {

    List<UserRegisterCheckVo> result=new ArrayList<>();

    List<UserRegisterRo> users = ro.getUsers();
    List<String> reqEmails = users.stream().map(UserRegisterRo::getEmail).toList();

    //已存在
    List<UserRegisterRo> addUsers = new ArrayList<>();
    List<UserSimpleInfoVo> userByEmails = apitableGrpcClientService.getUserByEmails(reqEmails);
    if(CollectionUtils.isNotEmpty(userByEmails)){
        List<String> existAll = userByEmails.stream().map(UserSimpleInfoVo::getEmail).toList();
        addUsers= users.stream().filter(x->!existAll.contains(x.getEmail())).toList();

        List<String> existNormal = userByEmails.stream().map(UserSimpleInfoVo::getEmail).toList();
        if(CollectionUtils.isNotEmpty(existNormal)){
            existNormal.forEach(x->{
                result.add(new UserRegisterCheckVo(x, RegisterResultType.FAIL.getId()));
            });
        }
    }

    if(CollectionUtils.isNotEmpty(addUsers)){
        addUsers.forEach(u -> {
            result.add(new UserRegisterCheckVo(u.getEmail(),RegisterResultType.SUCCESS.getId()));
        });
    }

    return result;

}


private List<UserRegisterCheckVo> checkRegisterUsersIn(UsersCreateRo ro) {

    List<UserRegisterCheckVo> result=new ArrayList<>();

    List<UserRegisterRo> users = ro.getUsers();
    List<String> reqEmails = users.stream().map(UserRegisterRo::getEmail).toList();

    //已存在
    List<UserRegisterRo> addUsers = new ArrayList<>();
    List<UserRegisterRo> recoverUsers = new ArrayList<>();
    List<UserSimpleInfoVo> userByEmails = apitableGrpcClientService.getUserByEmails(reqEmails);
    if(CollectionUtils.isNotEmpty(userByEmails)){
        List<String> existAll = userByEmails.stream().map(UserSimpleInfoVo::getEmail).toList();
        addUsers= users.stream().filter(x->!existAll.contains(x.getEmail())).toList();

        List<String> existNormal = userByEmails.stream().filter(x -> x.getStatus() == 0).map(UserSimpleInfoVo::getEmail).toList();
        if(CollectionUtils.isNotEmpty(existNormal)){
            existNormal.forEach(x->{
                result.add(new UserRegisterCheckVo(x, RegisterResultType.FAIL.getId()));
            });
        }

        List<String> existDisable = userByEmails.stream().filter(x -> x.getStatus() == 1).map(UserSimpleInfoVo::getEmail).toList();
        if(CollectionUtils.isNotEmpty(existDisable)){
            recoverUsers= users.stream().filter(x->existDisable.contains(x.getEmail())).toList();
        }

    }else{
        addUsers=users;
    }

    //expat小组
    Set<String> contractorUserEmails = new HashSet<>();
    List<MattermostGroupResp> usersWithTeam = getUsersWithTeam(mattermostProperties.getMmXTeamId());
    List<MattermostGroupResp> contractorTeam =
            usersWithTeam.stream().filter(t -> t.getDisplaygroupname().toLowerCase().startsWith("expat")).toList();
    if(CollectionUtils.isNotEmpty(contractorTeam)){
        contractorTeam.forEach(ct->{
            List<MattermostGroupResp.UserSimpleResp> expatUsers = ct.getUsers();
            if(CollectionUtils.isNotEmpty(expatUsers)){
                expatUsers.forEach(user-> contractorUserEmails.add(user.getEmail()));
            }
        });
    }


    //可新建
    if(CollectionUtils.isNotEmpty(addUsers)){
        addUsers.forEach(u -> {
            Integer checkResult = RegisterResultType.SUCCESS.getId();
            if (contractorUserEmails.contains(u.getEmail())) {
                checkResult = RegisterResultType.SUCCESS_FROM_EXPAT.getId();
            }
            result.add(new UserRegisterCheckVo(u.getEmail(),checkResult));
        });
    }

