package com.yottastudios.ns.collabspace.consumer.listener.treenode;

import com.yottastudios.ns.collabspace.consumer.handle.PermissionSyncHandler;
import com.yottastudios.ns.collabspace.consumer.handle.TreeNodePathSyncHandler;
import com.yottastudios.ns.collabspace.consumer.ws.TreeNodeWsNotifyService;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.BaseEventListener;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode.TreeNodeAddedEvent;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.stereotype.Component;

@Slf4j
@Component
@ConditionalOnProperty(name = "mq.enabled", havingValue = "true", matchIfMissing = true)
public class TreeNodeAddedEventListener extends BaseEventListener<TreeNodeAddedEvent> {

    @Resource
    private TreeNodePathSyncHandler pathHandler;

    @Resource
    private PermissionSyncHandler permissionHandler;

    @Resource
    private TreeNodeWsNotifyService wsNotifyService;

    @Override
    protected void handleEvent(TreeNodeAddedEvent event) {
        try {
            pathHandler.handleNodeAdded(event);
        } catch (Exception e) {
            log.error("handleNodeAdded failed: nodeId={}", event.getNodeId(), e);
        }

        try {
            log.info("handleNodeAdded permission event: nodeId={}, parentId={}", event.getNodeId(), event.getParentId());
            permissionHandler.handleTreeNodeEvent(event);
        } catch (Exception e) {
            log.error("handleNodeAdded permission sync failed: nodeId={}", event.getNodeId(), e);
        }

        try {
            wsNotifyService.notifyAdded(event);
        } catch (Exception e) {
            log.error("handleNodeAdded websocket notify failed: nodeId={}", event.getNodeId(), e);
        }
    }
}

