+package com.yottastudios.ns.collabspace.consumer.ws;
+
+import lombok.AllArgsConstructor;
+import lombok.Builder;
+import lombok.Data;
+import lombok.NoArgsConstructor;
+
+/**
+ * 推送给前端的树节点变更消息体（最小可用结构）。
+ */
+@Data
+@Builder
+@NoArgsConstructor
+@AllArgsConstructor
+public class TreeNodeWsChangeData {
+    /**
+     * 变更动作：ADDED / BATCH_MOVED / DELETED
+     */
+    private String action;
+
+    /**
+     * 树/空间标识（当前事件模型里对应 TreeNodeEvent.treeId）
+     */
+    private String treeId;
+
+    private String traceId;
+
+    private Long operatorId;
+
+    private String eventTriggerSource;
+
+    /**
+     * 事件发生时间（毫秒）
+     */
+    private Long timestamp;
+
+    /**
+     * 具体 payload：added/moved/deleted 不同
+     */
+    private Object payload;
+}
+
