package com.yottastudios.ns.collabspace.workspace.manager.query.impl;

import com.github.benmanes.caffeine.cache.Cache;
import com.github.benmanes.caffeine.cache.Caffeine;
import com.yottastudios.ns.collabspace.control.infrastructure.ControlRoleDict;
import com.yottastudios.ns.collabspace.control.infrastructure.ControlType;
import com.yottastudios.ns.collabspace.control.infrastructure.policy.SpacePermissionPolicy;
import com.yottastudios.ns.collabspace.control.infrastructure.role.ControlRole;
import com.yottastudios.ns.collabspace.control.infrastructure.role.NodeRoleLevel;
import com.yottastudios.ns.collabspace.control.infrastructure.role.SpacePolicyEnforcedControlRole;
import com.yottastudios.ns.collabspace.space.manager.query.SpacePermissionPolicyQueryManager;
import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeUserRoleCacheQueryManager;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeUserRoleCacheEntity;
import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeQueryManager;
import com.yottastudios.ns.collabspace.workspace.service.ISpaceNodeUserRoleCacheService;
import jakarta.annotation.Resource;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.stereotype.Service;

import java.time.Duration;
import java.util.ArrayList;
import java.util.LinkedHashSet;
import java.util.List;
import java.util.Map;
import java.util.Set;

@Service
public class SpaceNodeUserRoleCacheQueryManagerImpl implements SpaceNodeUserRoleCacheQueryManager {

    @Resource
    private ISpaceNodeUserRoleCacheService spaceNodeUserRoleCacheService;
    @Resource
    private SpaceNodeQueryManager spaceNodeQueryManager;
    @Resource
    private SpacePermissionPolicyQueryManager spacePermissionPolicyQueryManager;

    private final Cache<String, ControlRoleDict> roleDictCache = Caffeine.newBuilder()
            .maximumSize(10_000)
            .expireAfterWrite(Duration.ofSeconds(30))
            .build();

    @Override
    public List<Long> listUserIdsBySpaceNodeIdsAndMinRole(List<Long> spaceNodeIds, NodeRoleLevel minRole) {
        return spaceNodeUserRoleCacheService.listUserIdsByspaceNodeIdsAndMinRole(spaceNodeIds, minRole);
    }

    @Override
    public ControlRoleDict fetchSpaceNodeRoleCached(Long userId, List<Long> spaceNodeIds) {
        if (userId == null || CollectionUtils.isEmpty(spaceNodeIds)) {
            return ControlRoleDict.create();
        }
        List<Long> normalizedSpaceNodeIds = normalizeSpaceNodeIds(spaceNodeIds);
        if (normalizedSpaceNodeIds.isEmpty()) {
            return ControlRoleDict.create();
        }
        String cacheKey = buildRoleCacheKey(userId, normalizedSpaceNodeIds);
        ControlRoleDict roleDict = roleDictCache.get(cacheKey, key -> loadRoleDict(userId, normalizedSpaceNodeIds));
        if (roleDict == null) {
            return ControlRoleDict.create();
        }
        return roleDict.clone();
    }

    private ControlRoleDict loadRoleDict(Long userId, List<Long> spaceNodeIds) {
        List<SpaceNodeUserRoleCacheEntity> entities = spaceNodeUserRoleCacheService.getByUserAndNodes(userId, spaceNodeIds);
        ControlRoleDict dict = ControlRoleDict.create();
        if (CollectionUtils.isEmpty(entities)) {
            return dict;
        }
        for (SpaceNodeUserRoleCacheEntity entity : entities) {
            if (entity == null || entity.getSpaceNodeId() == null || entity.getRoleLevel() == null) {
                continue;
            }
            ControlRole role = NodeRoleLevel.fromLevel(entity.getRoleLevel()).toControlRole();
            if (role == null) {
                continue;
            }
            dict.put(entity.getSpaceNodeId().toString(), role);
        }
        return resetPermissionsBySpacePolicy(dict, spaceNodeIds);
    }

    private ControlRoleDict resetPermissionsBySpacePolicy(ControlRoleDict dict, List<Long> spaceNodeIds) {
        if (dict == null || dict.isEmpty()) {
            return dict;
        }
        Map<String, List<Long>> spaceMap = spaceNodeQueryManager.getSpaceIdToSpaceNodeIdMap(spaceNodeIds);
        Map<String, SpacePermissionPolicy> policyMap = spacePermissionPolicyQueryManager
                .getPolicyMapBySpaceIdsCached(ControlType.SPACE_NODE.getVal(), spaceMap.keySet());
        for (Map.Entry<String, List<Long>> entry : spaceMap.entrySet()) {
            SpacePermissionPolicy policy = policyMap.get(entry.getKey());
            List<Long> nodeIds = entry.getValue();
            if (nodeIds == null) {
                continue;
            }
            for (Long nodeId : nodeIds) {
                ControlRole base = dict.get(nodeId.toString());
                if (base == null) {
                    continue;
                }
                dict.put(nodeId.toString(), new SpacePolicyEnforcedControlRole(base, policy));
            }
        }
        return dict;
    }

    private String buildRoleCacheKey(Long userId, List<Long> spaceNodeIds) {
        StringBuilder idsPart = new StringBuilder();
        for (int i = 0; i < spaceNodeIds.size(); i++) {
            if (i > 0) {
                idsPart.append(',');
            }
            idsPart.append(spaceNodeIds.get(i));
        }
        return userId + "|" + idsPart;
    }

    private List<Long> normalizeSpaceNodeIds(List<Long> spaceNodeIds) {
        Set<Long> deduplicated = new LinkedHashSet<>();
        for (Long spaceNodeId : spaceNodeIds) {
            if (spaceNodeId != null) {
                deduplicated.add(spaceNodeId);
            }
        }
        List<Long> normalized = new ArrayList<>(deduplicated);
        normalized.sort(Long::compareTo);
        return normalized;
    }
}

