package com.yottastudios.ns.collabspace.starter.socketio.core;

import lombok.Data;

/**
 * 通用返回给前端的websocket数据结构
 */
@Data
public class WebSocketResponseModel {

    private String message;
    private int status;
    private String type;
    private Object data;

    // 私有构造函数，强制使用builder
    private WebSocketResponseModel() {}

    private WebSocketResponseModel(String message, int status, String type, Object data) {
        this.message = message;
        this.status = status;
        this.type = type;
        this.data = data;
    }

    /**
     * 创建构建器
     */
    public static Builder builder() {
        return new Builder();
    }

    /**
     * 快速创建成功响应
     */
    public static WebSocketResponseModel success(String message, Object data) {
        return builder()
                .message(message)
                .status(200)
                .type(MessageTypeEnum.CONNECT_SUCCESS.getType())
                .data(data)
                .build();
    }

    /**
     * 快速创建错误响应
     */
    public static WebSocketResponseModel error(String message, int status) {
        return builder()
                .message(message)
                .status(status)
                .type(MessageTypeEnum.CONNECT_ERROR.getType())
                .build();
    }


    /**
     * 快速创建心跳响应
     */
    public static WebSocketResponseModel heartbeat() {
        return builder()
                .message("pong")
                .status(200)
                .type(MessageTypeEnum.CONNECT_HEART.getType())
                .build();
    }

    /**
     * 构建器类
     */
    public static class Builder {
        private String message;
        private int status;
        private String type;
        private Object data;

        /**
         * 设置消息内容
         */
        public Builder message(String message) {
            this.message = message;
            return this;
        }

        /**
         * 设置状态码
         */
        public Builder status(int status) {
            this.status = status;
            return this;
        }

        /**
         * 设置类型
         */
        public Builder type(String type) {
            this.type = type;
            return this;
        }

        /**
         * 设置数据
         */
        public Builder data(Object data) {
            this.data = data;
            return this;
        }

        /**
         * 构建最终对象
         */
        public WebSocketResponseModel build() {
            return new WebSocketResponseModel(message, status, type, data);
        }
    }

}

