  1→package com.yottastudios.ns.collabspace.consumer.ws;
  2→
  3→import cn.hutool.json.JSONUtil;
  4→import com.yottastudios.ns.collabspace.base.config.NodeKeyType;
  5→import com.yottastudios.ns.collabspace.base.entity.NodeEntity;
  6→import com.yottastudios.ns.collabspace.base.manager.TreeNodeTemplate;
  7→import com.yottastudios.ns.collabspace.base.service.INodeService;
  8→import com.yottastudios.ns.collabspace.control.infrastructure.role.NodeRoleLevel;
  9→import com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode.TreeNodeAddedEvent;
 10→import com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode.TreeNodeBatchMovedEvent;
 11→import com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode.TreeNodeDeletedEvent;
 12→import com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode.TreeNodeEvent;
 13→import com.yottastudios.ns.collabspace.starter.socketio.core.MessageTypeEnum;
 14→import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketHandler;
 15→import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketResponseModel;
 16→import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
 17→import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeUserRoleCacheQueryManager;
 18→import jakarta.annotation.Resource;
 19→import lombok.extern.slf4j.Slf4j;
 20→import org.apache.commons.collections4.CollectionUtils;
 21→import org.springframework.stereotype.Component;
 22→
 23→import java.util.ArrayList;
 24→import java.util.HashMap;
 25→import java.util.List;
 26→import java.util.Map;
 27→import java.util.Objects;
 28→import java.util.stream.Collectors;
 29→
 30→import static com.yottastudios.ns.collabspace.core.support.tree.v2.DefaultTreeBuildFactory.ROOT_PARENT_ID;
 31→
 32→/**
 33→ * 树节点事件 -> WebSocket 推送。
 34→ * 仅推送给对相关节点有 READER 及以上权限的用户（复用 SpaceNodeUserRoleCacheQueryManager 的权限逻辑）。
 35→ */
 36→@Slf4j
 37→@Component
 38→public class TreeNodeWsNotifyService {
 39→
 40→    @Resource
 41→    private WebSocketHandler webSocketHandler;
 42→
 43→    @Resource
 44→    private SpaceNodeUserRoleCacheQueryManager spaceNodeUserRoleCacheQueryManager;
 45→
 46→    @Resource
 47→    private TreeNodeTemplate treeNodeTemplate;
 48→
 49→    @Resource
 50→    private INodeService nodeService;
 51→
 52→    public void notifyAdded(TreeNodeAddedEvent event) {
 53→        if (!shouldNotify(event)) {
 54→            return;
 55→        }
 56→        Map<String, Object> payload = new HashMap<>();
 57→        payload.put("nodeId", event.getNodeId());
 58→        payload.put("parentId", event.getParentId());
 59→        payload.put("relId", event.getRelId());
 60→
 61→        send("ADDED", event, payload);
 62→    }
 63→
 64→    public void notifyBatchMoved(TreeNodeBatchMovedEvent event) {
 65→        if (!shouldNotify(event)) {
 66→            return;
 67→        }
 68→        Map<String, Object> payload = new HashMap<>();
 69→        payload.put("newParentId", event.getNewParentId());
 70→        payload.put("movedNodes", event.getMovedNodes());
 71→
 72→        send("BATCH_MOVED", event, payload);
 73→    }
 74→
 75→    public void notifyDeleted(TreeNodeDeletedEvent event) {
 76→        if (!shouldNotify(event)) {
 77→            return;
 78→        }
 79→        Map<String, Object> payload = new HashMap<>();
 80→        payload.put("nodeId", event.getNodeId());
 81→        payload.put("parentId", event.getParentId());
 82→        payload.put("nodeName", event.getNodeName());
 83→        payload.put("relId", event.getRelId());
 84→
 85→        send("DELETED", event, payload);
 86→    }
 87→
 88→    private boolean shouldNotify(TreeNodeEvent event) {
 89→        if (event == null) {
 90→            return false;
 91→        }
 92→        // 只推送 space node 树（与 PermissionSyncHandler 的判定保持一致）
 93→        if (event.getNodeKey() == null || !NodeKeyType.AIO_FILE_TREE.getValue().equals(event.getNodeKey())) {
 94→            return false;
 95→        }
 96→        // 仅对 SpaceNodeEntity 的树节点事件推送（与 TreeNodePathSyncHandler 的判定风格一致）
 97→        return SpaceNodeEntity.class.getName().equals(event.getEntityClassName());
 98→    }
 99→
100→    /** 日志前缀，便于 grep 排查 */
101→    private static final String LOG_PREFIX = "[1592-change]";
102→
103→    private void send(String action, TreeNodeEvent event, Object payload) {
104→        String treeId = event.getTreeId();
105→        String traceId = event.getTraceId();
106→        Long operatorId = event.getOperatorId();
107→
108→        List<Long> spaceNodeIds = collectSpaceNodeIds(action, event);
109→        if (CollectionUtils.isEmpty(spaceNodeIds)) {
110→            log.warn("{} skip reason=no_space_node_ids action={} treeId={} traceId={} operatorId={}",
111→                    LOG_PREFIX, action, treeId, traceId, operatorId);
112→            return;
113→        }
114→
115→        List<Long> userIds = spaceNodeUserRoleCacheQueryManager.listUserIdsBySpaceNodeIdsAndMinRole(spaceNodeIds, NodeRoleLevel.READER);
116→        if (CollectionUtils.isEmpty(userIds)) {
117→            log.warn("{} skip reason=no_permitted_users action={} treeId={} spaceNodeIds={} traceId={} operatorId={}",
118→                    LOG_PREFIX, action, treeId, spaceNodeIds, traceId, operatorId);
119→            return;
120→        }
121→
122→        TreeNodeWsChangeData data = TreeNodeWsChangeData.builder()
123→                .action(action)
124→                .treeId(event.getTreeId())
125→                .traceId(event.getTraceId())
126→                .operatorId(event.getOperatorId())
127→                .eventTriggerSource(event.getEventTriggerSource())
128→                .timestamp(System.currentTimeMillis())
129→                .payload(payload)
130→                .build();
131→
132→        WebSocketResponseModel resp = WebSocketResponseModel.builder()
133→                .type(MessageTypeEnum.TREE_NODE_CHANGED.getType())
134→                .message("tree node changed")
135→                .status(200)
136→                .data(data)
137→                .build();
138→
139→        String msg = JSONUtil.toJsonStr(resp);
140→        int sendCount;
141→        try {
142→            sendCount = webSocketHandler.sendUsersToWebSocketClient(msg, userIds);
143→        } catch (Exception e) {
144→            log.error("{} push_failed action={} treeId={} traceId={} operatorId={} targetUserCount={} spaceNodeIds={}",
145→                    LOG_PREFIX, action, treeId, traceId, operatorId, userIds.size(), spaceNodeIds, e);
146→            return;
147→        }
148→        String idSummary = formatLogIdSummary(action, event, spaceNodeIds);
149→        log.info("{} pushed action={} treeId={} traceId={} operatorId={} {} targetUserCount={} sendCount={}",
150→                LOG_PREFIX, action, treeId, traceId, operatorId, idSummary, userIds.size(), sendCount);
151→    }
152→
153→    /** 用于日志的 id 摘要，便于排查 */
154→    private String formatLogIdSummary(String action, TreeNodeEvent event, List<Long> spaceNodeIds) {
155→        if ("BATCH_MOVED".equals(action)) {
156→            TreeNodeBatchMovedEvent moved = (TreeNodeBatchMovedEvent) event;
157→            int movedCount = moved.getMovedNodes() != null ? moved.getMovedNodes().size() : 0;
158→            return "movedCount=" + movedCount + " newParentId=" + moved.getNewParentId() + " spaceNodeIds=" + spaceNodeIds;
159→        }
160→        return "relId=" + event.getRelId() + " spaceNodeIds=" + spaceNodeIds;
161→    }
162→
163→    /**
164→     * 根据事件类型收集需要做权限过滤的 spaceNodeIds（SpaceNodeEntity.id）
165→     */
166→    private List<Long> collectSpaceNodeIds(String action, TreeNodeEvent event) {
167→        List<Long> ids = new ArrayList<>();
168→        switch (action) {
169→            case "ADDED" -> {
170→                Long relId = event.getRelId();
171→                if (relId != null) {
172→                    ids.add(relId);
173→                    // 父节点：能看见父节点的用户需要收到新增子节点通知
174→                    NodeEntity parent = treeNodeTemplate.getParentNodeByRelId(relId);
175→                    if (parent != null && parent.getRelId() != null) {
176→                        ids.add(parent.getRelId());
177→                    }
178→                }
179→            }
180→            case "DELETED" -> {
181→                if (event.getRelId() != null) {
182→                    ids.add(event.getRelId());
183→                }
184→            }
185→            case "BATCH_MOVED" -> {
186→                TreeNodeBatchMovedEvent movedEvent = (TreeNodeBatchMovedEvent) event;
187→                if (CollectionUtils.isNotEmpty(movedEvent.getMovedNodes())) {
188→                    ids.addAll(movedEvent.getMovedNodes().stream()
189→                            .map(TreeNodeBatchMovedEvent.MovedNodeInfo::getRelId)
190→                            .filter(Objects::nonNull)
191→                            .toList());
192→                }
193→                // 新父节点：能看见目标位置的用户需要收到移动通知
194→                Long newParentId = movedEvent.getNewParentId();
195→                if (newParentId != null && !Objects.equals(newParentId, ROOT_PARENT_ID)) {
196→                    NodeEntity newParent = nodeService.getById(newParentId);
197→                    if (newParent != null && newParent.getRelId() != null) {
198→                        ids.add(newParent.getRelId());
199→                    }
200→                }
201→            }
202→            default -> { /* 未知 action 不收集 */ }
203→        }
204→        return ids.stream().filter(Objects::nonNull).distinct().toList();
205→    }
206→}
