package com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode;

import com.yottastudios.ns.collabspace.interfaces.eventbus.model.EventBusEventType;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Data;
import lombok.EqualsAndHashCode;
import lombok.NoArgsConstructor;
import lombok.experimental.SuperBuilder;

import java.util.List;

@Data
@EqualsAndHashCode(callSuper = true)
@NoArgsConstructor
@SuperBuilder
public class TreeNodeBatchMovedEvent extends TreeNodeEvent {
    private Long newParentId;
    private List<MovedNodeInfo> movedNodes;

    @Data
    @Builder
    @NoArgsConstructor
    @AllArgsConstructor
    public static class MovedNodeInfo {
        private Long nodeId;
        private Long relId;
        private Long oldParentId;
    }

    @Override
    public EventBusEventType getEventType() {
        return EventBusEventType.TREE_NODE_BATCH_MOVED;
    }
}

