package com.yottastudios.ns.collabspace.consumer.ws;

import cn.hutool.json.JSONUtil;
import com.yottastudios.ns.collabspace.base.config.NodeKeyType;
import com.yottastudios.ns.collabspace.base.entity.NodeEntity;
import com.yottastudios.ns.collabspace.base.manager.TreeNodeTemplate;
import com.yottastudios.ns.collabspace.base.service.INodeService;
import com.yottastudios.ns.collabspace.control.infrastructure.role.NodeRoleLevel;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode.TreeNodeAddedEvent;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode.TreeNodeBatchMovedEvent;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode.TreeNodeDeletedEvent;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode.TreeNodeEvent;
import com.yottastudios.ns.collabspace.starter.socketio.core.MessageTypeEnum;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketHandler;
import com.yottastudios.ns.collabspace.starter.socketio.core.WebSocketResponseModel;
import com.yottastudios.ns.collabspace.workspace.entity.SpaceNodeEntity;
import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeUserRoleCacheQueryManager;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.stereotype.Component;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.stream.Collectors;

import static com.yottastudios.ns.collabspace.core.support.tree.v2.DefaultTreeBuildFactory.ROOT_PARENT_ID;

/**
 * 树节点事件 -> WebSocket 推送。
 * 仅推送给对相关节点有 READER 及以上权限的用户（复用 SpaceNodeUserRoleCacheQueryManager 的权限逻辑）。
 */
@Slf4j
@Component
public class TreeNodeWsNotifyService {

    @Resource
    private WebSocketHandler webSocketHandler;

    @Resource
    private SpaceNodeUserRoleCacheQueryManager spaceNodeUserRoleCacheQueryManager;

    @Resource
    private TreeNodeTemplate treeNodeTemplate;

    @Resource
    private INodeService nodeService;

    public void notifyAdded(TreeNodeAddedEvent event) {
        if (!shouldNotify(event)) {
            return;
        }
        Map<String, Object> payload = new HashMap<>();
        // Long → String 防止前端 JS 精度丢失（超过 Number.MAX_SAFE_INTEGER）
        payload.put("nodeId", longToStr(event.getNodeId()));
        payload.put("parentId", longToStr(event.getParentId()));
        payload.put("relId", longToStr(event.getRelId()));

        send("ADDED", event, payload);
    }

    public void notifyBatchMoved(TreeNodeBatchMovedEvent event) {
        if (!shouldNotify(event)) {
            return;
        }
        Map<String, Object> payload = new HashMap<>();
        // Long → String 防止前端 JS 精度丢失
        payload.put("newParentId", longToStr(event.getNewParentId()));
        payload.put("movedNodes", toMovedNodePayload(event.getMovedNodes()));

        send("BATCH_MOVED", event, payload);
    }

    public void notifyDeleted(TreeNodeDeletedEvent event) {
        if (!shouldNotify(event)) {
            return;
        }
        Map<String, Object> payload = new HashMap<>();
        // Long → String 防止前端 JS 精度丢失
        payload.put("nodeId", longToStr(event.getNodeId()));
        payload.put("parentId", longToStr(event.getParentId()));
        payload.put("nodeName", event.getNodeName());
        payload.put("relId", longToStr(event.getRelId()));

        send("DELETED", event, payload);
    }

    private boolean shouldNotify(TreeNodeEvent event) {
        if (event == null) {
            return false;
        }
        // 只推送 space node 树（与 PermissionSyncHandler 的判定保持一致）
        if (event.getNodeKey() == null || !NodeKeyType.AIO_FILE_TREE.getValue().equals(event.getNodeKey())) {
            return false;
        }
        // 仅对 SpaceNodeEntity 的树节点事件推送（与 TreeNodePathSyncHandler 的判定风格一致）
        return SpaceNodeEntity.class.getName().equals(event.getEntityClassName());
    }

    /** 日志前缀，便于 grep 排查 */
    private static final String LOG_PREFIX = "[1592-change]";

    private void send(String action, TreeNodeEvent event, Object payload) {
        String treeId = event.getTreeId();
        String traceId = event.getTraceId();
        Long operatorId = event.getOperatorId();

        List<Long> spaceNodeIds = collectSpaceNodeIds(action, event);
        if (CollectionUtils.isEmpty(spaceNodeIds)) {
            log.warn("{} skip reason=no_space_node_ids action={} treeId={} traceId={} operatorId={}",
                    LOG_PREFIX, action, treeId, traceId, operatorId);
            return;
        }

        List<Long> userIds = spaceNodeUserRoleCacheQueryManager.listUserIdsBySpaceNodeIdsAndMinRole(spaceNodeIds, NodeRoleLevel.READER);
        if (CollectionUtils.isEmpty(userIds)) {
            log.warn("{} skip reason=no_permitted_users action={} treeId={} spaceNodeIds={} traceId={} operatorId={}",
                    LOG_PREFIX, action, treeId, spaceNodeIds, traceId, operatorId);
            return;
        }

        TreeNodeWsChangeData data = TreeNodeWsChangeData.builder()
                .action(action)
                .treeId(event.getTreeId())
                .traceId(event.getTraceId())
                .operatorId(longToStr(event.getOperatorId()))
                .eventTriggerSource(event.getEventTriggerSource())
                .timestamp(System.currentTimeMillis())
                .payload(payload)
                .build();

        WebSocketResponseModel resp = WebSocketResponseModel.builder()
                .type(MessageTypeEnum.TREE_NODE_CHANGED.getType())
                .message("tree node changed")
                .status(200)
                .data(data)
                .build();

        String msg = JSONUtil.toJsonStr(resp);
        int sendCount;
        try {
            sendCount = webSocketHandler.sendUsersToWebSocketClient(msg, userIds);
        } catch (Exception e) {
            log.error("{} push_failed action={} treeId={} traceId={} operatorId={} targetUserCount={} spaceNodeIds={}",
                    LOG_PREFIX, action, treeId, traceId, operatorId, userIds.size(), spaceNodeIds, e);
            return;
        }
        String idSummary = formatLogIdSummary(action, event, spaceNodeIds);
        log.info("{} pushed action={} treeId={} traceId={} operatorId={} {} targetUserCount={} sendCount={}",
                LOG_PREFIX, action, treeId, traceId, operatorId, idSummary, userIds.size(), sendCount);
    }

    /** 用于日志的 id 摘要，便于排查 */
    private String formatLogIdSummary(String action, TreeNodeEvent event, List<Long> spaceNodeIds) {
        if ("BATCH_MOVED".equals(action)) {
            TreeNodeBatchMovedEvent moved = (TreeNodeBatchMovedEvent) event;
            int movedCount = moved.getMovedNodes() != null ? moved.getMovedNodes().size() : 0;
            return "movedCount=" + movedCount + " newParentId=" + moved.getNewParentId() + " spaceNodeIds=" + spaceNodeIds;
        }
        return "relId=" + event.getRelId() + " spaceNodeIds=" + spaceNodeIds;
    }

    /**
     * 根据事件类型收集需要做权限过滤的 spaceNodeIds（SpaceNodeEntity.id）
     */
    private List<Long> collectSpaceNodeIds(String action, TreeNodeEvent event) {
        List<Long> ids = new ArrayList<>();
        switch (action) {
            case "ADDED" -> {
                Long relId = event.getRelId();
                if (relId != null) {
                    ids.add(relId);
                    // 父节点：能看见父节点的用户需要收到新增子节点通知
                    NodeEntity parent = treeNodeTemplate.getParentNodeByRelId(relId);
                    if (parent != null && parent.getRelId() != null) {
                        ids.add(parent.getRelId());
                    }
                }
            }
            case "DELETED" -> {
                if (event.getRelId() != null) {
                    ids.add(event.getRelId());
                }
            }
            case "BATCH_MOVED" -> {
                TreeNodeBatchMovedEvent movedEvent = (TreeNodeBatchMovedEvent) event;
