package com.yottastudios.ns.collabspace.base.vo;

import com.fasterxml.jackson.databind.annotation.JsonSerialize;
import com.yottastudios.ns.collabspace.base.service.RelIdProvider;
import com.yottastudios.ns.collabspace.core.support.tree.v2.Tree;
import com.yottastudios.ns.collabspace.shared.support.serializer.LongToStringSerializer;
import com.yottastudios.ns.collabspace.shared.support.serializer.NullCollectionSerializer;
import io.swagger.v3.oas.annotations.media.Schema;
import lombok.Data;
import lombok.NoArgsConstructor;
import lombok.AllArgsConstructor;
import com.yottastudios.ns.collabspace.base.entity.NodeEntity;

import java.util.List;

@Data
@NoArgsConstructor
@AllArgsConstructor
public class TreeNode<T extends RelIdProvider> implements Tree {

    @JsonSerialize(using = LongToStringSerializer.class)
    @Schema(description = "ID", example = "1")
    private Long id;

    @JsonSerialize(using = LongToStringSerializer.class)
    @Schema(description = "Parent ID", example = "1")
    private Long parentId;

    @JsonSerialize(using = LongToStringSerializer.class)
    @Schema(description = "Previous Node ID", example = "1")
    private Long preId;

    @Schema(description = "Tree ID", example = "1")
    private String treeId;

    @JsonSerialize(using = LongToStringSerializer.class)
    @Schema(description = "Related Object ID", example = "1")
    private Long relId;

    @Schema(description = "Node Key", example = "1")
    private Integer nodeKey;

    @Schema(description = "Node Type", example = "folder")
    private String nodeType;

    @Schema(description = "Data associated with this node, can vary depending on nodeType")
    private T data;

    @Schema(description = "Error code when node not accessible: 600=node not exist, 601=no doc permission, 403=no space permission. Null when success.")
    private Integer errorCode;

    @JsonSerialize(nullsUsing = NullCollectionSerializer.class)
    @Schema(description = "Child Nodes")
    private List<TreeNode<T>> children;

    @Override
    public Long getId() {
        return this.id;
    }

    @Override
    public Long getParentId() {
        return this.parentId;
    }

    @Override
    public void setParentId(Long parentId) {
        this.parentId = parentId;
    }

    @Override
    public Long getPreId() {
        return this.preId;
    }

    @Override
    public void setPreId(Long preId) {
        this.preId = preId;
    }

    @Override
    public List<TreeNode<T>> getChildren() {
        return this.children;
    }

    @Override
    public void setChildren(List children) {
        this.children = children;
    }

    public TreeNode(NodeEntity entity, T nodeData) {
        this.id = entity.getId();
        this.parentId = entity.getParentId();
        this.preId = entity.getPreId();
        this.relId = entity.getRelId();
        this.nodeKey = entity.getNodeKey();
        this.nodeType = entity.getNodeType();
        this.treeId = entity.getTreeId();
        this.data = nodeData;
    }

    public TreeNode(NodeEntity entity) {
        this.id = entity.getId();
        this.parentId = entity.getParentId();
        this.preId = entity.getPreId();
        this.relId = entity.getRelId();
        this.nodeKey = entity.getNodeKey();
        this.nodeType = entity.getNodeType();
        this.treeId = entity.getTreeId();
    }

    public TreeNode<T> setDataBasedOnNodeType(T nodeData) {
        this.data = nodeData;
        return this;
    }
}

