 45→
 46→    @Override
 47→    public <T extends RelIdProvider> List<TreeNode<T>> buildNodeTree(List<T> list) {
 48→        if (CollectionUtils.isEmpty(list)) return new ArrayList<>();
 49→
 50→        List<Long> ids = list.stream().map(RelIdProvider::getRelId).collect(Collectors.toList());
 51→        List<NodeEntity> nodeEntities = nodeService.listByRelIds(ids);
 52→        return buildNodeTree(list, nodeEntities, ROOT_PARENT_ID);
 53→    }
 54→
 55→    @Override
 56→    public <T extends RelIdProvider> List<TreeNode<T>> buildNodeTree(List<T> list, List<NodeEntity> nodeEntities, Long rootId) {
 57→        List<TreeNode<T>> nodeTrees = new ArrayList<>();
 58→        if (CollectionUtils.isEmpty(list)) return nodeTrees;
 59→
 60→        Map<Long, NodeEntity> nodeMap = nodeEntities.stream()
 61→                .collect(Collectors.toMap(NodeEntity::getRelId, nodeEntity -> nodeEntity));
 62→
 63→        nodeTrees = list.stream()
 64→                .map(item -> {
 65→                    Long relId = item.getRelId();
 66→                    NodeEntity nodeEntity = nodeMap.get(relId);
 67→                    return new TreeNode<>(nodeEntity, item);
 68→                }).collect(Collectors.toList());
 69→
 70→        return TreeUtil.build(nodeTrees, rootId);
 71→    }
 72→
 73→    @Override
 74→    public NodeEntity addNode(Long parentId, String treeId, Long relId, Class<?> entityClass) {
 75→        Integer nodeKey = NodeKeyMapping.getNodeKeyByClass(entityClass);
 76→        String nodeType = entityClass.getSimpleName();
 77→
 78→        NodeEntity result = lockService.tryLockWithRetry(
 79→                RedisConstants.getNodeTreeOperateKey(treeId, nodeKey.toString()),
 80→                () -> {
 81→                    Long preId = selectLastNode(treeId, nodeKey, parentId);
 82→                    NodeEntity entity = NodeEntity.builder()
 83→                            .preId(preId)
 84→                            .parentId(parentId)
 85→                            .treeId(treeId)
 86→                            .relId(relId)
 87→                            .nodeKey(nodeKey)
 88→                            .nodeType(nodeType)
 89→                            .build();
 90→                    nodeService.save(entity);
 91→                    return entity;
 92→                }
 93→        );
 94→
 95→        EventBusEvent event = TreeNodeAddedEvent.builder()
 96→                .nodeId(result.getId())
 97→                .relId(relId)
 98→                .treeId(treeId)
 99→                .nodeKey(nodeKey)
100→                .entityClassName(entityClass.getName())
101→                .parentId(parentId)
102→                .build();
103→        eventBusFacade.onEventAfterCommit(event);
104→
105→        return result;
106→    }
107→
108→    @Override
109→    public List<NodeEntity> addSubtree(Long parentId, String treeId, List<SubtreeNode> roots, Class<?> entityClass) {
110→        if (CollectionUtils.isEmpty(roots)) {
111→            return List.of();
112→        }
113→
114→        Integer nodeKey = NodeKeyMapping.getNodeKeyByClass(entityClass);
115→        String nodeType = entityClass.getSimpleName();
116→
117→        List<NodeEntity> results = lockService.tryLockWithRetry(
118→                RedisConstants.getNodeTreeOperateKey(treeId, nodeKey.toString()),
119→                () -> {
120→                    Long preId = selectLastNode(treeId, nodeKey, parentId);
121→                    List<NodeEntity> allEntities = new ArrayList<>();
122→                    buildSubtreeEntities(parentId, preId, roots, treeId, nodeKey, nodeType, allEntities);
123→                    nodeService.saveBatch(allEntities);
124→                    return allEntities;
125→                }
126→        );
127→
128→        for (NodeEntity node : results) {
129→            EventBusEvent event = TreeNodeAddedEvent.builder()
130→                    .nodeId(node.getId())
131→                    .relId(node.getRelId())
132→                    .treeId(treeId)
133→                    .nodeKey(nodeKey)
134→                    .entityClassName(entityClass.getName())
135→                    .parentId(node.getParentId())
136→                    .build();
137→            eventBusFacade.onEventAfterCommit(event);
138→        }
139→
140→        return results;
141→    }
142→
143→    private void buildSubtreeEntities(Long parentNodeId, Long initialPreId, List<SubtreeNode> siblings,
144→                                      String treeId, Integer nodeKey, String nodeType,
145→                                      List<NodeEntity> collector) {
146→        Long preId = initialPreId;
147→        for (SubtreeNode node : siblings) {
148→            Long nodeId = IdWorker.getId();
149→            NodeEntity entity = NodeEntity.builder()
150→                    .id(nodeId)
151→                    .preId(preId)
152→                    .parentId(parentNodeId)
153→                    .treeId(treeId)
154→                    .relId(node.relId())
155→                    .nodeKey(nodeKey)
156→                    .nodeType(nodeType)
157→                    .build();
158→            collector.add(entity);
159→            preId = nodeId;
160→
161→            if (CollectionUtils.isNotEmpty(node.children())) {
162→                buildSubtreeEntities(nodeId, ROOT_PARENT_ID, node.children(), treeId, nodeKey, nodeType, collector);
163→            }
164→        }
165→    }
166→
167→    @Transactional
168→    @Override
169→    public void deleteNodeByRelId(Long relId) {
170→        NodeEntity entity = nodeService.getByRelId(relId);
171→        ExceptionUtil.isNotNull(entity, DatabaseException.QUERY_EMPTY_BY_ID);
172→
173→        Long nodeId = entity.getId();
174→        Long parentId = entity.getParentId();
175→        String treeId = entity.getTreeId();
176→        Integer nodeKey = entity.getNodeKey();
177→        String entityClassName = NodeKeyMapping.getClassByNodeKey(nodeKey).getName();
178→
179→        lockService.tryLockWithRetry(
180→                RedisConstants.getNodeTreeOperateKey(entity.getTreeId(),entity.getNodeKey().toString()),
181→                () -> {
182→                    updateOrderOnDelete(entity);
183→                    nodeService.removeById(entity);
184→                    return null;
185→                }
186→        );
187→
188→        EventBusEvent event = TreeNodeDeletedEvent.builder()
189→                .nodeId(nodeId)
190→                .relId(relId)
191→                .treeId(treeId)
192→                .nodeKey(nodeKey)
193→                .entityClassName(entityClassName)
194→                .parentId(parentId)
195→                .build();
196→        eventBusFacade.onEventAfterCommit(event);
197→    }
198→
199→    @Transactional
200→    @Override
201→    public NodeEntity moveNode(String treeId, Long nodeId, Long newPreId, Long newParentId, Class<?> entityClass) {
202→        Long resolvedPreId = newPreId == null ? ROOT_PARENT_ID : newPreId;
203→        moveNodes(treeId, List.of(nodeId), resolvedPreId, newParentId, entityClass);
204→        NodeEntity moved = nodeService.getById(nodeId);
205→        ExceptionUtil.isNotNull(moved, DatabaseException.QUERY_EMPTY_BY_ID);
206→        return moved;
207→    }
208→
209→    @Transactional
210→    @Override
211→    public void moveChildNodesToRootByParentId(Long parentRelId) {
212→        NodeEntity parentNode = nodeService.getByRelId(parentRelId);
213→        ExceptionUtil.isNotNull(parentNode, DatabaseException.QUERY_EMPTY_BY_ID);
214→        Long parentId = parentNode.getId();
215→        NodeEntity firstChild = nodeService.getFirstChildNodeByParentId(parentId, parentNode.getTreeId(), parentNode.getNodeKey());
216→        ExceptionUtil.isNotNull(firstChild, DatabaseException.QUERY_EMPTY_BY_ID);
217→
218→        lockService.tryLockWithRetry(
219→                RedisConstants.getNodeTreeOperateKey(firstChild.getTreeId(),firstChild.getNodeKey().toString()),
220→                () -> {
221→                    Long lastRootId = selectLastNode(firstChild.getTreeId(), firstChild.getNodeKey(), ROOT_PARENT_ID);
222→                    List<NodeEntity> childNodes = nodeService.getByTreeIdAndParentIdAndNodeKey(firstChild.getTreeId(), parentId, firstChild.getNodeKey());
223→                    for (NodeEntity childNode : childNodes) {
224→                        if (Objects.equals(childNode.getId(), firstChild.getId())) {
225→                            childNode.setPreId(lastRootId);
226→                        }
227→                        childNode.setParentId(ROOT_PARENT_ID);
228→                    }
229→                    nodeService.updateBatchById(childNodes);
230→                    return null;
231→                }
232→        );
233→    }
234→
235→    @Override
236→    public List<NodeEntity> getParentNodesByRelId(Long relId) {
237→        List<NodeEntity> ancestors = nodeService.listAncestorsByRelId(relId);
238→        if (ancestors.isEmpty()) {
239→            return new ArrayList<>();
240→        }
241→        NodeEntity current = null;
242→        Map<Long, NodeEntity> idToNode = new HashMap<>();
243→        for (NodeEntity n : ancestors) {
244→            if (n == null || n.getId() == null) continue;
245→            idToNode.put(n.getId(), n);
246→            if (Objects.equals(n.getRelId(), relId)) {
247→                current = n;
248→            }
249→        }
250→        if (current == null) {
251→            return ancestors;
252→        }
253→
254→        List<NodeEntity> orderedNodes = new ArrayList<>();
255→        Set<Long> visited = new HashSet<>();
256→        visited.add(current.getId());
257→        orderedNodes.add(current);
258→
259→        Long parentId = current.getParentId();
260→        while (parentId != null && !Objects.equals(parentId, ROOT_PARENT_ID)) {
261→            if (!visited.add(parentId)) break;
262→            NodeEntity parent = idToNode.get(parentId);
263→            if (parent == null) break;
264→            orderedNodes.add(parent);
265→            parentId = parent.getParentId();
266→        }
267→        return orderedNodes;
268→    }
269→
270→    @Override
271→    public NodeEntity getParentNodeByRelId(Long relId) {
272→        NodeEntity currentNode = nodeService.getByRelId(relId);
273→        if (currentNode == null || Objects.equals(currentNode.getParentId(), ROOT_PARENT_ID)) return null;
274→
275→        return nodeService.getById(currentNode.getParentId());
276→    }
277→
278→    @Override
279→    public List<NodeEntity> getParentPathNodesByRelIds(List<Long> relIds) {
280→        List<NodeEntity> nodes = nodeService.listByRelIds(relIds);
281→        if (CollectionUtils.isEmpty(nodes)) return List.of();
282→
283→        Map<Long, NodeEntity> nodeIdToNodeMap = new HashMap<>();
284→        Set<Long> parentIds = new HashSet<>();
285→        // init
286→        for (NodeEntity node : nodes) {
287→            if (!ROOT_PARENT_ID.equals(node.getParentId())) {
288→                parentIds.add(node.getParentId());
289→            }
290→            nodeIdToNodeMap.put(node.getId(), node);
291→        }
292→        // find parents
293→        while (!parentIds.isEmpty()) {
294→            List<NodeEntity> parentNodes = nodeService.listByIds(parentIds);
295→            if (CollectionUtils.isEmpty(parentNodes)) break;
296→
297→            parentIds.clear();
298→            for (NodeEntity parentNode : parentNodes) {
299→                if (nodeIdToNodeMap.containsKey(parentNode.getId())) continue;
300→
301→                if (!nodeIdToNodeMap.containsKey(parentNode.getParentId())
302→                        && !ROOT_PARENT_ID.equals(parentNode.getParentId())) {
303→                    parentIds.add(parentNode.getParentId());
304→                }
305→                nodeIdToNodeMap.put(parentNode.getId(), parentNode);
306→            }
307→        }
308→        return new ArrayList<>(nodeIdToNodeMap.values());
309→    }
310→
311→    @Override
312→    public Boolean isNodeBelongRootFolder(Long relId) {
313→        NodeEntity entity = nodeService.getByRelId(relId);
314→        ExceptionUtil.isNotNull(entity, DatabaseException.QUERY_EMPTY_BY_ID);
315→        return Objects.equals(entity.getParentId(), ROOT_PARENT_ID);
316→    }
317→
318→
319→    private void adjustNodeOrder(String treeId, Integer nodeKey, NodeEntity entity, Long newPreId) {
320→        if (newPreId == null) {
321→            newPreId = ROOT_PARENT_ID;
322→        }
323→        Long currentPreId = entity.getPreId();
324→        if (Objects.equals(currentPreId, newPreId) || Objects.equals(entity.getId(), newPreId)) {
325→            return;
326→        }
327→
328→        if (!ROOT_PARENT_ID.equals(newPreId)) {
329→            NodeEntity preEntity = nodeService.getById(newPreId);
330→            ExceptionUtil.isNotNull(preEntity, DatabaseException.QUERY_EMPTY_BY_ID);
331→            ExceptionUtil.isTrue(Objects.equals(preEntity.getParentId(), entity.getParentId()), TreeNodeException.SAME_PARENT_ONLY);
332→        }
333→
334→        updatePreviousNode(treeId, nodeKey, entity.getId(), currentPreId, newPreId, entity.getParentId());
335→        nodeService.updatePreId(newPreId, entity.getId());
336→    }
337→
338→    private void adjustNodeLevel(String treeId, Integer nodeKey, NodeEntity entity, Long newParentId) {
339→        if (newParentId == null) {
340→            newParentId = ROOT_PARENT_ID;
341→        }
342→        Long currentParentId = entity.getParentId();
343→        if (Objects.equals(currentParentId, newParentId) || Objects.equals(entity.getId(), newParentId)) {
344→            return;
345→        }
346→
347→        updateOrderOnDelete(entity);
348→        Long preId = selectLastNode(treeId, nodeKey, newParentId);
349→
350→        entity.setPreId(preId);
351→        entity.setParentId(newParentId);
352→        nodeService.updateById(entity);
353→    }
354→
355→    private void updatePreviousNode(String treeId, Integer nodeKey, Long nodeId, Long currentPreId, Long newPreId, Long parentId) {
356→        NodeEntity entityPointingToCurrent = nodeService.getNodeByPreId(treeId, nodeKey, parentId, nodeId);
357→        if (entityPointingToCurrent != null) {
358→            nodeService.updatePreId(currentPreId, entityPointingToCurrent.getId());
359→        }
360→
361→        NodeEntity newEntityPointingToCurrent = nodeService.getNodeByPreId(treeId, nodeKey, parentId, newPreId);
362→        if (newEntityPointingToCurrent != null) {
363→            nodeService.updatePreId(nodeId, newEntityPointingToCurrent.getId());
364→        }
365→    }
366→
367→    private void updateOrderOnDelete(NodeEntity entity) {
368→        NodeEntity entityPointingToCurrent = nodeService.getNodeByPreId(entity.getTreeId(), entity.getNodeKey(), entity.getParentId(), entity.getId());
369→        if (entityPointingToCurrent != null) {
370→            Long currentPreId = entity.getPreId() != null ? entity.getPreId() : 0L;
371→            nodeService.updatePreId(currentPreId, entityPointingToCurrent.getId());
372→        }
373→    }
374→
375→    private Long selectLastNode(String treeId, Integer nodeKey, Long parentId) {
376→        if (parentId == null) parentId = ROOT_PARENT_ID;
377→        List<NodeEntity> nodes = nodeService.getByTreeIdAndParentIdAndNodeKey(treeId, parentId, nodeKey);
378→        if (CollectionUtils.isEmpty(nodes)) return ROOT_PARENT_ID;
379→        List<NodeTreeVo> treeVos = nodes.stream()
380→                .map(NodeTreeVo::new).toList();
381→        return TreeUtil.build(treeVos, parentId).getLast().getId();
382→    }
