385→    @Transactional
386→    @Override
387→    public void recoverNodeByRelId(Long relId) {
388→        NodeEntity entity = nodeService.getByRelIdAllStatus(relId);
389→        ExceptionUtil.isNotNull(entity, DatabaseException.QUERY_EMPTY_BY_ID);
390→
391→        lockService.tryLockWithRetry(
392→                RedisConstants.getNodeTreeOperateKey(entity.getTreeId(),entity.getNodeKey().toString()),
393→                () -> {
394→                    // 校验父节点是否存在，不存在则恢复到根节点, 这是为了尽量恢复到删前的原目录下
395→                    Long parentId = entity.getParentId();
396→                    // 直接放在第一个位置, 就不恢复到原有顺序了
397→                    entity.setPreId(ROOT_PARENT_ID);
398→                    NodeEntity parentNode = nodeService.getById(parentId);
399→                    if (parentNode == null) {
400→                        parentId = ROOT_PARENT_ID;
401→                        entity.setParentId(parentId);
402→                    }
403→
404→                    NodeEntity firstChild = nodeService.getFirstChildNodeByParentId(parentId, entity.getTreeId(), entity.getNodeKey());
405→
406→                    nodeService.updateById(entity);
407→                    if (firstChild != null) {
408→                        // 当父节点下存在有效(未删除且在首位)节点时，需要重新维护顺序, 将要恢复的节点放到第一位, 插到有效节点前
409→                        firstChild.setPreId(entity.getId());
410→                        nodeService.updateById(firstChild);
411→                    }
412→                    nodeService.recoverNodeByRelId(relId);
413→                    return null;
414→                }
415→        );
416→    }
417→
418→    @Override
419→    public List<NodeEntity> listSubtreeByRelId(Long relId) {
420→        return nodeService.listSubtreeByRelId(relId);
421→    }
422→
423→    @Transactional
424→    @Override
425→    public void moveNodes(String treeId, List<Long> nodeIds, Long newPreId, Long newParentId, Class<?> entityClass) {
426→        if (CollectionUtils.isEmpty(nodeIds)) {
427→            log.warn("moveNodes aborted: nodeIds is empty");
428→            return;
429→        }
430→
431→        // 去重并保持原始顺序
432→        LinkedHashSet<Long> orderedDistinctIds = new LinkedHashSet<>();
433→        for (Long id : nodeIds) {
434→            if (id != null) orderedDistinctIds.add(id);
435→        }
436→        if (orderedDistinctIds.isEmpty()) {
437→            log.warn("moveNodes aborted: no valid nodeIds after deduplication");
438→            return;
439→        }
440→
441→        Integer nodeKey = NodeKeyMapping.getNodeKeyByClass(entityClass);
442→
443→        List<Long> orderedIds = new ArrayList<>(orderedDistinctIds);
444→        List<NodeEntity> entities = nodeService.listByIds(orderedIds);
445→        ExceptionUtil.isFalse(CollectionUtils.isEmpty(entities) || entities.size() != orderedIds.size(), DatabaseException.QUERY_EMPTY_BY_ID);
446→
447→        Map<Long, NodeEntity> idToEntity = entities.stream().collect(Collectors.toMap(NodeEntity::getId, e -> e));
448→        List<NodeEntity> orderedEntities = orderedIds.stream().map(idToEntity::get).toList();
449→
450→        // 被操作的节点必须在同一颗树上
451→        for (NodeEntity e : orderedEntities) {
452→            ExceptionUtil.isFalse(!Objects.equals(treeId, e.getTreeId()), TreeNodeException.INVALID_TREE_ID);
453→            ExceptionUtil.isFalse(!Objects.equals(nodeKey, e.getNodeKey()), TreeNodeException.INVALID_NODE_KEY);
454→        }
455→
456→        Long targetParentId = newParentId == null ? ROOT_PARENT_ID : newParentId;
457→        if (!Objects.equals(targetParentId, ROOT_PARENT_ID)) {
458→            NodeEntity targetParent = nodeService.getById(targetParentId);
459→            ExceptionUtil.isNotNull(targetParent, DatabaseException.QUERY_EMPTY_BY_ID);
460→            ExceptionUtil.isFalse(!Objects.equals(treeId, targetParent.getTreeId()), TreeNodeException.INVALID_PARENT_TREE_ID);
461→            ExceptionUtil.isFalse(!Objects.equals(nodeKey, targetParent.getNodeKey()), TreeNodeException.INVALID_PARENT_NODE_KEY);
462→        }
463→
464→        // 根据 nodeIds 的原始顺序筛选需要移动的顶层节点：父不在集合中，或链断（父不存在）也视为顶层
465→        Set<Long> idSet = new HashSet<>(orderedIds);
466→        List<NodeEntity> topLevelToMove = new ArrayList<>();
467→        for (NodeEntity e : orderedEntities) {
468→            Long pid = e.getParentId();
469→            if (pid == null || Objects.equals(pid, ROOT_PARENT_ID)) {
470→                topLevelToMove.add(e);
471→                continue;
472→            }
473→            if (!idSet.contains(pid)) {
474→                topLevelToMove.add(e);
475→            }
476→        }
477→        if (topLevelToMove.isEmpty()) {
478→            log.warn("moveNodes aborted: no top-level nodes resolved from nodeIds");
479→            return;
480→        }
481→
482→        Long initialPreId;
483→        if (newPreId == null) {
484→            initialPreId = selectLastNode(treeId, nodeKey, targetParentId);
485→        } else if (Objects.equals(newPreId, 0L)) {
486→            initialPreId = ROOT_PARENT_ID;
487→        } else {
488→            NodeEntity preEntity = nodeService.getById(newPreId);
489→            ExceptionUtil.isNotNull(preEntity, DatabaseException.QUERY_EMPTY_BY_ID);
490→            ExceptionUtil.isFalse(!Objects.equals(preEntity.getTreeId(), treeId), TreeNodeException.INVALID_PRE_TREE_ID);
491→            ExceptionUtil.isFalse(!Objects.equals(preEntity.getNodeKey(), nodeKey), TreeNodeException.INVALID_PRE_NODE_KEY);
492→            ExceptionUtil.isFalse(!Objects.equals(preEntity.getParentId(), targetParentId), TreeNodeException.PRE_NOT_IN_TARGET_PARENT);
493→            Set<Long> topIds = topLevelToMove.stream().map(NodeEntity::getId).collect(Collectors.toSet());
494→            ExceptionUtil.isFalse(topIds.contains(newPreId), TreeNodeException.PRE_CANNOT_BE_MOVING_NODE);
495→            initialPreId = newPreId;
496→        }
497→
498→        // 循环校验：目标父不能是任一移动节点或其子孙
499→        // todo 减少开销
500→        for (NodeEntity e : topLevelToMove) {
501→            ExceptionUtil.isFalse(Objects.equals(e.getId(), targetParentId), TreeNodeException.PARENT_CYCLE);
502→            List<NodeEntity> subtree = nodeService.listSubtreeByRelId(e.getRelId());
503→            boolean parentInSubtree = subtree.stream().anyMatch(n -> Objects.equals(n.getId(), targetParentId));
504→            ExceptionUtil.isFalse(parentInSubtree, TreeNodeException.PARENT_IN_SUBTREE);
505→        }
506→
507→        Map<Long, Long> nodeIdToOldParentId = new HashMap<>();
508→        for (NodeEntity e : topLevelToMove) {
509→            nodeIdToOldParentId.put(e.getId(), e.getParentId());
510→        }
511→
512→        lockService.tryLockWithRetry(
513→                RedisConstants.getNodeTreeOperateKey(treeId, nodeKey.toString()),
514→                () -> {
515→                    Long prev = initialPreId;
516→                    for (NodeEntity e : topLevelToMove) {
517→                        e = nodeService.getById(e.getId());
518→                        adjustNodeLevel(treeId, nodeKey, e, targetParentId);
519→                        adjustNodeOrder(treeId, nodeKey, e, prev);
520→                        prev = e.getId();
521→                    }
522→                    return null;
523→                }
524→        );
525→
526→        List<TreeNodeBatchMovedEvent.MovedNodeInfo> movedInfoList = new ArrayList<>();
527→        for (NodeEntity e : topLevelToMove) {
528→            Long oldParentId = nodeIdToOldParentId.get(e.getId());
529→            if (!Objects.equals(oldParentId, targetParentId)) {
530→                movedInfoList.add(TreeNodeBatchMovedEvent.MovedNodeInfo.builder()
531→                        .relId(e.getRelId())
532→                        .oldParentId(oldParentId)
533→                        .nodeId(e.getId())
534→                        .build());
535→            }
536→        }
537→
538→        if (!movedInfoList.isEmpty()) {
539→            EventBusEvent event = TreeNodeBatchMovedEvent.builder()
540→                    .treeId(treeId)
541→                    .nodeKey(nodeKey)
542→                    .entityClassName(entityClass.getName())
543→                    .newParentId(targetParentId)
544→                    .movedNodes(movedInfoList)
545→                    .build();
546→            eventBusFacade.onEventAfterCommit(event);
547→        }
548→    }
549→}
