package com.yottastudios.ns.collabspace.base.manager.impl;

import com.baomidou.mybatisplus.core.toolkit.IdWorker;
import com.yottastudios.ns.collabspace.base.config.NodeKeyMapping;
import com.yottastudios.ns.collabspace.base.entity.NodeEntity;
import com.yottastudios.ns.collabspace.base.enums.DatabaseException;
import com.yottastudios.ns.collabspace.base.enums.TreeNodeException;
import com.yottastudios.ns.collabspace.base.manager.TreeNodeTemplate;
import com.yottastudios.ns.collabspace.base.service.INodeService;
import com.yottastudios.ns.collabspace.base.service.RelIdProvider;
import com.yottastudios.ns.collabspace.base.vo.NodeTreeVo;
import com.yottastudios.ns.collabspace.base.vo.TreeNode;
import com.yottastudios.ns.collabspace.core.constants.RedisConstants;
import com.yottastudios.ns.collabspace.core.support.tree.v2.TreeUtil;
import com.yottastudios.ns.collabspace.core.util.ExceptionUtil;
import com.yottastudios.ns.collabspace.interfaces.eventbus.facade.EventBusFacade;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.EventBusEvent;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode.TreeNodeAddedEvent;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode.TreeNodeBatchMovedEvent;
import com.yottastudios.ns.collabspace.interfaces.eventbus.model.treenode.TreeNodeDeletedEvent;
import com.yottastudios.ns.collabspace.shared.redis.LockService;
import jakarta.annotation.Resource;
import lombok.extern.slf4j.Slf4j;
import org.apache.commons.collections4.CollectionUtils;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.util.*;
import java.util.stream.Collectors;

import static com.yottastudios.ns.collabspace.core.support.tree.v2.DefaultTreeBuildFactory.ROOT_PARENT_ID;

@Service
@Slf4j
public class TreeNodeTemplateImpl implements TreeNodeTemplate {

    @Resource
    private INodeService nodeService;

    @Resource
    private LockService lockService;

    @Resource
    private EventBusFacade eventBusFacade;

    @Override
    public <T extends RelIdProvider> List<TreeNode<T>> buildNodeTree(List<T> list) {
        if (CollectionUtils.isEmpty(list)) return new ArrayList<>();

        List<Long> ids = list.stream().map(RelIdProvider::getRelId).collect(Collectors.toList());
        List<NodeEntity> nodeEntities = nodeService.listByRelIds(ids);
        return buildNodeTree(list, nodeEntities, ROOT_PARENT_ID);
    }

    @Override
    public <T extends RelIdProvider> List<TreeNode<T>> buildNodeTree(List<T> list, List<NodeEntity> nodeEntities, Long rootId) {
        List<TreeNode<T>> nodeTrees = new ArrayList<>();
        if (CollectionUtils.isEmpty(list)) return nodeTrees;

        Map<Long, NodeEntity> nodeMap = nodeEntities.stream()
                .collect(Collectors.toMap(NodeEntity::getRelId, nodeEntity -> nodeEntity));

        nodeTrees = list.stream()
                .map(item -> {
                    Long relId = item.getRelId();
                    NodeEntity nodeEntity = nodeMap.get(relId);
                    return new TreeNode<>(nodeEntity, item);
                }).collect(Collectors.toList());

        return TreeUtil.build(nodeTrees, rootId);
    }

    @Override
    public NodeEntity addNode(Long parentId, String treeId, Long relId, Class<?> entityClass) {
        Integer nodeKey = NodeKeyMapping.getNodeKeyByClass(entityClass);
        String nodeType = entityClass.getSimpleName();

        NodeEntity result = lockService.tryLockWithRetry(
                RedisConstants.getNodeTreeOperateKey(treeId, nodeKey.toString()),
                () -> {
                    Long preId = selectLastNode(treeId, nodeKey, parentId);
                    NodeEntity entity = NodeEntity.builder()
                            .preId(preId)
                            .parentId(parentId)
                            .treeId(treeId)
                            .relId(relId)
                            .nodeKey(nodeKey)
                            .nodeType(nodeType)
                            .build();
                    nodeService.save(entity);
                    return entity;
                }
        );

        EventBusEvent event = TreeNodeAddedEvent.builder()
                .nodeId(result.getId())
                .relId(relId)
                .treeId(treeId)
                .nodeKey(nodeKey)
                .entityClassName(entityClass.getName())
                .parentId(parentId)
                .build();
        eventBusFacade.onEventAfterCommit(event);

        return result;
    }

    @Override
    public List<NodeEntity> addSubtree(Long parentId, String treeId, List<SubtreeNode> roots, Class<?> entityClass) {
        if (CollectionUtils.isEmpty(roots)) {
            return List.of();
        }

        Integer nodeKey = NodeKeyMapping.getNodeKeyByClass(entityClass);
        String nodeType = entityClass.getSimpleName();

        List<NodeEntity> results = lockService.tryLockWithRetry(
                RedisConstants.getNodeTreeOperateKey(treeId, nodeKey.toString()),
                () -> {
                    Long preId = selectLastNode(treeId, nodeKey, parentId);
                    List<NodeEntity> allEntities = new ArrayList<>();
                    buildSubtreeEntities(parentId, preId, roots, treeId, nodeKey, nodeType, allEntities);
                    nodeService.saveBatch(allEntities);
                    return allEntities;
                }
        );

        for (NodeEntity node : results) {
            EventBusEvent event = TreeNodeAddedEvent.builder()
                    .nodeId(node.getId())
                    .relId(node.getRelId())
                    .treeId(treeId)
                    .nodeKey(nodeKey)
                    .entityClassName(entityClass.getName())
                    .parentId(node.getParentId())
                    .build();
            eventBusFacade.onEventAfterCommit(event);
        }

        return results;
    }

    private void buildSubtreeEntities(Long parentNodeId, Long initialPreId, List<SubtreeNode> siblings,
                                      String treeId, Integer nodeKey, String nodeType,
                                      List<NodeEntity> collector) {
        Long preId = initialPreId;
        for (SubtreeNode node : siblings) {
            Long nodeId = IdWorker.getId();
            NodeEntity entity = NodeEntity.builder()
                    .id(nodeId)
                    .preId(preId)
                    .parentId(parentNodeId)
                    .treeId(treeId)
                    .relId(node.relId())
                    .nodeKey(nodeKey)
                    .nodeType(nodeType)
                    .build();
            collector.add(entity);
            preId = nodeId;

            if (CollectionUtils.isNotEmpty(node.children())) {
                buildSubtreeEntities(nodeId, ROOT_PARENT_ID, node.children(), treeId, nodeKey, nodeType, collector);
            }
        }
    }

    @Transactional
    @Override
    public void deleteNodeByRelId(Long relId) {
        NodeEntity entity = nodeService.getByRelId(relId);
        ExceptionUtil.isNotNull(entity, DatabaseException.QUERY_EMPTY_BY_ID);

        Long nodeId = entity.getId();
        Long parentId = entity.getParentId();
        String treeId = entity.getTreeId();
        Integer nodeKey = entity.getNodeKey();
        String entityClassName = NodeKeyMapping.getClassByNodeKey(nodeKey).getName();

        lockService.tryLockWithRetry(
                RedisConstants.getNodeTreeOperateKey(entity.getTreeId(),entity.getNodeKey().toString()),
                () -> {
                    updateOrderOnDelete(entity);
                    nodeService.removeById(entity);
                    return null;
                }
        );

        EventBusEvent event = TreeNodeDeletedEvent.builder()
                .nodeId(nodeId)
                .relId(relId)
                .treeId(treeId)
                .nodeKey(nodeKey)
                .entityClassName(entityClassName)
                .parentId(parentId)
                .build();
        eventBusFacade.onEventAfterCommit(event);
    }

    @Transactional
    @Override
    public NodeEntity moveNode(String treeId, Long nodeId, Long newPreId, Long newParentId, Class<?> entityClass) {
        Long resolvedPreId = newPreId == null ? ROOT_PARENT_ID : newPreId;
        moveNodes(treeId, List.of(nodeId), resolvedPreId, newParentId, entityClass);
        NodeEntity moved = nodeService.getById(nodeId);
        ExceptionUtil.isNotNull(moved, DatabaseException.QUERY_EMPTY_BY_ID);
        return moved;
    }

    @Transactional
    @Override
    public void moveChildNodesToRootByParentId(Long parentRelId) {
        NodeEntity parentNode = nodeService.getByRelId(parentRelId);
        ExceptionUtil.isNotNull(parentNode, DatabaseException.QUERY_EMPTY_BY_ID);
        Long parentId = parentNode.getId();
        NodeEntity firstChild = nodeService.getFirstChildNodeByParentId(parentId, parentNode.getTreeId(), parentNode.getNodeKey());
        ExceptionUtil.isNotNull(firstChild, DatabaseException.QUERY_EMPTY_BY_ID);

        lockService.tryLockWithRetry(
                RedisConstants.getNodeTreeOperateKey(firstChild.getTreeId(),firstChild.getNodeKey().toString()),
                () -> {
                    Long lastRootId = selectLastNode(firstChild.getTreeId(), firstChild.getNodeKey(), ROOT_PARENT_ID);
                    List<NodeEntity> childNodes = nodeService.getByTreeIdAndParentIdAndNodeKey(firstChild.getTreeId(), parentId, firstChild.getNodeKey());
                    for (NodeEntity childNode : childNodes) {
                        if (Objects.equals(childNode.getId(), firstChild.getId())) {
                            childNode.setPreId(lastRootId);
                        }
                        childNode.setParentId(ROOT_PARENT_ID);
                    }
                    nodeService.updateBatchById(childNodes);
                    return null;
                }
        );
    }

    @Override
    public List<NodeEntity> getParentNodesByRelId(Long relId) {
        List<NodeEntity> ancestors = nodeService.listAncestorsByRelId(relId);
        if (ancestors.isEmpty()) {
            return new ArrayList<>();
        }
        NodeEntity current = null;
        Map<Long, NodeEntity> idToNode = new HashMap<>();
        for (NodeEntity n : ancestors) {
            if (n == null || n.getId() == null) continue;
            idToNode.put(n.getId(), n);
            if (Objects.equals(n.getRelId(), relId)) {
                current = n;
            }
        }
        if (current == null) {
            return ancestors;
        }

        List<NodeEntity> orderedNodes = new ArrayList<>();
        Set<Long> visited = new HashSet<>();
        visited.add(current.getId());
        orderedNodes.add(current);

        Long parentId = current.getParentId();
        while (parentId != null && !Objects.equals(parentId, ROOT_PARENT_ID)) {
            if (!visited.add(parentId)) break;
            NodeEntity parent = idToNode.get(parentId);
            if (parent == null) break;
            orderedNodes.add(parent);
            parentId = parent.getParentId();
        }
        return orderedNodes;
    }

    @Override
    public NodeEntity getParentNodeByRelId(Long relId) {
        NodeEntity currentNode = nodeService.getByRelId(relId);
        if (currentNode == null || Objects.equals(currentNode.getParentId(), ROOT_PARENT_ID)) return null;

        return nodeService.getById(currentNode.getParentId());
    }

    @Override
    public List<NodeEntity> getParentPathNodesByRelIds(List<Long> relIds) {
        List<NodeEntity> nodes = nodeService.listByRelIds(relIds);
        if (CollectionUtils.isEmpty(nodes)) return List.of();

        Map<Long, NodeEntity> nodeIdToNodeMap = new HashMap<>();
        Set<Long> parentIds = new HashSet<>();
        // init
        for (NodeEntity node : nodes) {
            if (!ROOT_PARENT_ID.equals(node.getParentId())) {
                parentIds.add(node.getParentId());
            }
            nodeIdToNodeMap.put(node.getId(), node);
        }
        // find parents
        while (!parentIds.isEmpty()) {
            List<NodeEntity> parentNodes = nodeService.listByIds(parentIds);
            if (CollectionUtils.isEmpty(parentNodes)) break;

            parentIds.clear();
            for (NodeEntity parentNode : parentNodes) {
                if (nodeIdToNodeMap.containsKey(parentNode.getId())) continue;

                if (!nodeIdToNodeMap.containsKey(parentNode.getParentId())
                        && !ROOT_PARENT_ID.equals(parentNode.getParentId())) {
                    parentIds.add(parentNode.getParentId());
                }
                nodeIdToNodeMap.put(parentNode.getId(), parentNode);
            }
        }
        return new ArrayList<>(nodeIdToNodeMap.values());
    }

    @Override
    public Boolean isNodeBelongRootFolder(Long relId) {
        NodeEntity entity = nodeService.getByRelId(relId);
        ExceptionUtil.isNotNull(entity, DatabaseException.QUERY_EMPTY_BY_ID);
        return Objects.equals(entity.getParentId(), ROOT_PARENT_ID);
    }


    private void adjustNodeOrder(String treeId, Integer nodeKey, NodeEntity entity, Long newPreId) {
        if (newPreId == null) {
            newPreId = ROOT_PARENT_ID;
        }
        Long currentPreId = entity.getPreId();
        if (Objects.equals(currentPreId, newPreId) || Objects.equals(entity.getId(), newPreId)) {
            return;
        }

        if (!ROOT_PARENT_ID.equals(newPreId)) {
            NodeEntity preEntity = nodeService.getById(newPreId);
            ExceptionUtil.isNotNull(preEntity, DatabaseException.QUERY_EMPTY_BY_ID);
            ExceptionUtil.isTrue(Objects.equals(preEntity.getParentId(), entity.getParentId()), TreeNodeException.SAME_PARENT_ONLY);
        }

        updatePreviousNode(treeId, nodeKey, entity.getId(), currentPreId, newPreId, entity.getParentId());
        nodeService.updatePreId(newPreId, entity.getId());
    }

    private void adjustNodeLevel(String treeId, Integer nodeKey, NodeEntity entity, Long newParentId) {
        if (newParentId == null) {
            newParentId = ROOT_PARENT_ID;
        }
        Long currentParentId = entity.getParentId();
        if (Objects.equals(currentParentId, newParentId) || Objects.equals(entity.getId(), newParentId)) {
            return;
        }

        updateOrderOnDelete(entity);
        Long preId = selectLastNode(treeId, nodeKey, newParentId);

        entity.setPreId(preId);
        entity.setParentId(newParentId);
        nodeService.updateById(entity);
    }

    private void updatePreviousNode(String treeId, Integer nodeKey, Long nodeId, Long currentPreId, Long newPreId, Long parentId) {
        NodeEntity entityPointingToCurrent = nodeService.getNodeByPreId(treeId, nodeKey, parentId, nodeId);
        if (entityPointingToCurrent != null) {
            nodeService.updatePreId(currentPreId, entityPointingToCurrent.getId());
        }

        NodeEntity newEntityPointingToCurrent = nodeService.getNodeByPreId(treeId, nodeKey, parentId, newPreId);
        if (newEntityPointingToCurrent != null) {
            nodeService.updatePreId(nodeId, newEntityPointingToCurrent.getId());
        }
    }

    private void updateOrderOnDelete(NodeEntity entity) {
        NodeEntity entityPointingToCurrent = nodeService.getNodeByPreId(entity.getTreeId(), entity.getNodeKey(), entity.getParentId(), entity.getId());
        if (entityPointingToCurrent != null) {
            Long currentPreId = entity.getPreId() != null ? entity.getPreId() : 0L;
            nodeService.updatePreId(currentPreId, entityPointingToCurrent.getId());
        }
    }

    private Long selectLastNode(String treeId, Integer nodeKey, Long parentId) {
        if (parentId == null) parentId = ROOT_PARENT_ID;
        List<NodeEntity> nodes = nodeService.getByTreeIdAndParentIdAndNodeKey(treeId, parentId, nodeKey);
        if (CollectionUtils.isEmpty(nodes)) return ROOT_PARENT_ID;
        List<NodeTreeVo> treeVos = nodes.stream()
                .map(NodeTreeVo::new).toList();
        return TreeUtil.build(treeVos, parentId).getLast().getId();
    }


    @Transactional
    @Override
    public void recoverNodeByRelId(Long relId) {
        NodeEntity entity = nodeService.getByRelIdAllStatus(relId);
        ExceptionUtil.isNotNull(entity, DatabaseException.QUERY_EMPTY_BY_ID);

        lockService.tryLockWithRetry(
                RedisConstants.getNodeTreeOperateKey(entity.getTreeId(),entity.getNodeKey().toString()),
                () -> {
                    // 校验父节点是否存在，不存在则恢复到根节点, 这是为了尽量恢复到删前的原目录下
                    Long parentId = entity.getParentId();
                    // 直接放在第一个位置, 就不恢复到原有顺序了
                    entity.setPreId(ROOT_PARENT_ID);
                    NodeEntity parentNode = nodeService.getById(parentId);
                    if (parentNode == null) {
                        parentId = ROOT_PARENT_ID;
                        entity.setParentId(parentId);
                    }

                    NodeEntity firstChild = nodeService.getFirstChildNodeByParentId(parentId, entity.getTreeId(), entity.getNodeKey());

                    nodeService.updateById(entity);
                    if (firstChild != null) {
                        // 当父节点下存在有效(未删除且在首位)节点时，需要重新维护顺序, 将要恢复的节点放到第一位, 插到有效节点前
                        firstChild.setPreId(entity.getId());
                        nodeService.updateById(firstChild);
                    }
                    nodeService.recoverNodeByRelId(relId);
                    return null;
                }
        );
    }

    @Override
    public List<NodeEntity> listSubtreeByRelId(Long relId) {
        return nodeService.listSubtreeByRelId(relId);
    }

    @Transactional
    @Override
    public void moveNodes(String treeId, List<Long> nodeIds, Long newPreId, Long newParentId, Class<?> entityClass) {
        if (CollectionUtils.isEmpty(nodeIds)) {
            log.warn("moveNodes aborted: nodeIds is empty");
            return;
        }

        // 去重并保持原始顺序
        LinkedHashSet<Long> orderedDistinctIds = new LinkedHashSet<>();
        for (Long id : nodeIds) {
            if (id != null) orderedDistinctIds.add(id);
        }
        if (orderedDistinctIds.isEmpty()) {
            log.warn("moveNodes aborted: no valid nodeIds after deduplication");
            return;
        }

        Integer nodeKey = NodeKeyMapping.getNodeKeyByClass(entityClass);

        List<Long> orderedIds = new ArrayList<>(orderedDistinctIds);
        List<NodeEntity> entities = nodeService.listByIds(orderedIds);
        ExceptionUtil.isFalse(CollectionUtils.isEmpty(entities) || entities.size() != orderedIds.size(), DatabaseException.QUERY_EMPTY_BY_ID);

        Map<Long, NodeEntity> idToEntity = entities.stream().collect(Collectors.toMap(NodeEntity::getId, e -> e));
        List<NodeEntity> orderedEntities = orderedIds.stream().map(idToEntity::get).toList();

        // 被操作的节点必须在同一颗树上
        for (NodeEntity e : orderedEntities) {
            ExceptionUtil.isFalse(!Objects.equals(treeId, e.getTreeId()), TreeNodeException.INVALID_TREE_ID);
            ExceptionUtil.isFalse(!Objects.equals(nodeKey, e.getNodeKey()), TreeNodeException.INVALID_NODE_KEY);
        }

        Long targetParentId = newParentId == null ? ROOT_PARENT_ID : newParentId;
        if (!Objects.equals(targetParentId, ROOT_PARENT_ID)) {
            NodeEntity targetParent = nodeService.getById(targetParentId);
            ExceptionUtil.isNotNull(targetParent, DatabaseException.QUERY_EMPTY_BY_ID);
            ExceptionUtil.isFalse(!Objects.equals(treeId, targetParent.getTreeId()), TreeNodeException.INVALID_PARENT_TREE_ID);
            ExceptionUtil.isFalse(!Objects.equals(nodeKey, targetParent.getNodeKey()), TreeNodeException.INVALID_PARENT_NODE_KEY);
        }

        // 根据 nodeIds 的原始顺序筛选需要移动的顶层节点：父不在集合中，或链断（父不存在）也视为顶层
        Set<Long> idSet = new HashSet<>(orderedIds);
        List<NodeEntity> topLevelToMove = new ArrayList<>();
        for (NodeEntity e : orderedEntities) {
            Long pid = e.getParentId();
            if (pid == null || Objects.equals(pid, ROOT_PARENT_ID)) {
                topLevelToMove.add(e);
                continue;
            }
            if (!idSet.contains(pid)) {
                topLevelToMove.add(e);
            }
        }
        if (topLevelToMove.isEmpty()) {
            log.warn("moveNodes aborted: no top-level nodes resolved from nodeIds");
            return;
        }

        Long initialPreId;
        if (newPreId == null) {
            initialPreId = selectLastNode(treeId, nodeKey, targetParentId);
        } else if (Objects.equals(newPreId, 0L)) {
            initialPreId = ROOT_PARENT_ID;
        } else {
            NodeEntity preEntity = nodeService.getById(newPreId);
            ExceptionUtil.isNotNull(preEntity, DatabaseException.QUERY_EMPTY_BY_ID);
            ExceptionUtil.isFalse(!Objects.equals(preEntity.getTreeId(), treeId), TreeNodeException.INVALID_PRE_TREE_ID);
            ExceptionUtil.isFalse(!Objects.equals(preEntity.getNodeKey(), nodeKey), TreeNodeException.INVALID_PRE_NODE_KEY);
            ExceptionUtil.isFalse(!Objects.equals(preEntity.getParentId(), targetParentId), TreeNodeException.PRE_NOT_IN_TARGET_PARENT);
            Set<Long> topIds = topLevelToMove.stream().map(NodeEntity::getId).collect(Collectors.toSet());
            ExceptionUtil.isFalse(topIds.contains(newPreId), TreeNodeException.PRE_CANNOT_BE_MOVING_NODE);
            initialPreId = newPreId;
        }

        // 循环校验：目标父不能是任一移动节点或其子孙
        // todo 减少开销
        for (NodeEntity e : topLevelToMove) {
            ExceptionUtil.isFalse(Objects.equals(e.getId(), targetParentId), TreeNodeException.PARENT_CYCLE);
            List<NodeEntity> subtree = nodeService.listSubtreeByRelId(e.getRelId());
            boolean parentInSubtree = subtree.stream().anyMatch(n -> Objects.equals(n.getId(), targetParentId));
            ExceptionUtil.isFalse(parentInSubtree, TreeNodeException.PARENT_IN_SUBTREE);
        }

        Map<Long, Long> nodeIdToOldParentId = new HashMap<>();
        for (NodeEntity e : topLevelToMove) {
            nodeIdToOldParentId.put(e.getId(), e.getParentId());
        }

        lockService.tryLockWithRetry(
                RedisConstants.getNodeTreeOperateKey(treeId, nodeKey.toString()),
                () -> {
                    Long prev = initialPreId;
                    for (NodeEntity e : topLevelToMove) {
                        e = nodeService.getById(e.getId());
                        adjustNodeLevel(treeId, nodeKey, e, targetParentId);
                        adjustNodeOrder(treeId, nodeKey, e, prev);
                        prev = e.getId();
                    }
                    return null;
                }
        );

        List<TreeNodeBatchMovedEvent.MovedNodeInfo> movedInfoList = new ArrayList<>();
        for (NodeEntity e : topLevelToMove) {
            Long oldParentId = nodeIdToOldParentId.get(e.getId());
            if (!Objects.equals(oldParentId, targetParentId)) {
                movedInfoList.add(TreeNodeBatchMovedEvent.MovedNodeInfo.builder()
                        .relId(e.getRelId())
                        .oldParentId(oldParentId)
                        .nodeId(e.getId())
                        .build());
            }
        }

        if (!movedInfoList.isEmpty()) {
            EventBusEvent event = TreeNodeBatchMovedEvent.builder()
                    .treeId(treeId)
                    .nodeKey(nodeKey)
                    .entityClassName(entityClass.getName())
                    .newParentId(targetParentId)
                    .movedNodes(movedInfoList)
                    .build();
            eventBusFacade.onEventAfterCommit(event);
        }
    }
}

