package com.yottastudios.ns.collabspace.workspace.vo;

import com.fasterxml.jackson.databind.annotation.JsonSerialize;
import com.yottastudios.ns.collabspace.base.vo.TreeNode;
import com.yottastudios.ns.collabspace.shared.support.serializer.LongToStringSerializer;
import com.yottastudios.ns.collabspace.shared.support.serializer.NullCollectionSerializer;
import io.swagger.v3.oas.annotations.media.Schema;
import lombok.Data;

import java.util.List;
import java.util.stream.Collectors;

/**
 * spaceNodeTree 接口专用树节点 VO，去掉前端不使用的字段（treeId、relId、nodeKey、preId）
 */
@Data
@Schema(name = "SpaceNodeTreeNodeVo")
public class SpaceNodeTreeNodeVo {

    @JsonSerialize(using = LongToStringSerializer.class)
    @Schema(description = "ID")
    private Long id;

    @JsonSerialize(using = LongToStringSerializer.class)
    @Schema(description = "Parent ID")
    private Long parentId;

    @Schema(description = "Node Type")
    private String nodeType;

    @Schema(description = "Data associated with this node")
    private SpaceNodeVo data;

    @Schema(description = "Error code: 600=not exist, 601=no doc permission, 403=no space permission")
    private Integer errorCode;

    @JsonSerialize(nullsUsing = NullCollectionSerializer.class)
    @Schema(description = "Child Nodes")
    private List<SpaceNodeTreeNodeVo> children;

    public static SpaceNodeTreeNodeVo from(TreeNode<SpaceNodeVo> node) {
        if (node == null) {
            return null;
        }
        SpaceNodeTreeNodeVo vo = new SpaceNodeTreeNodeVo();
        vo.setId(node.getId());
        vo.setParentId(node.getParentId());
        vo.setNodeType(node.getNodeType());
        vo.setData(node.getData());
        vo.setErrorCode(node.getErrorCode());
        if (node.getChildren() != null) {
            vo.setChildren(node.getChildren().stream()
                    .map(SpaceNodeTreeNodeVo::from)
                    .collect(Collectors.toList()));
        }
        return vo;
    }

    public static List<SpaceNodeTreeNodeVo> fromList(List<TreeNode<SpaceNodeVo>> nodes) {
        if (nodes == null) {
            return List.of();
        }
        return nodes.stream()
                .map(SpaceNodeTreeNodeVo::from)
                .collect(Collectors.toList());
    }
}

