package com.yottastudios.ns.collabspace.workspace.controller;

import com.fasterxml.jackson.core.JsonProcessingException;
import com.yottastudios.ns.collabspace.base.entity.NodeEntity;
import com.yottastudios.ns.collabspace.base.service.INodeService;
import com.yottastudios.ns.collabspace.base.vo.TreeNode;
import com.yottastudios.ns.collabspace.control.check.PermissionChecker;
import com.yottastudios.ns.collabspace.control.infrastructure.permission.NodePermission;
import com.yottastudios.ns.collabspace.core.exception.BusinessException;
import com.yottastudios.ns.collabspace.core.support.ResponseData;
import com.yottastudios.ns.collabspace.grpc.ICollabspaceGrpcClientService;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.ApiResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.GetResource;
import com.yottastudios.ns.collabspace.shared.component.scanner.annotation.PostResource;
import com.yottastudios.ns.collabspace.shared.constants.ParamsConstants;
import com.yottastudios.ns.collabspace.shared.context.SessionContext;
import com.yottastudios.ns.collabspace.shared.holder.SpaceHolder;
import com.yottastudios.ns.collabspace.workspace.enums.SpaceNodeException;
import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeImportTaskQueryManager;
import com.yottastudios.ns.collabspace.workspace.manager.query.SpaceNodeQueryManager;
import com.yottastudios.ns.collabspace.workspace.manager.update.SpaceNodeImportTaskUpdateManager;
import com.yottastudios.ns.collabspace.workspace.manager.update.SpaceNodeUpdateManager;
import com.yottastudios.ns.collabspace.workspace.ro.*;
import com.yottastudios.ns.collabspace.workspace.service.DataCheckService;
import com.yottastudios.ns.collabspace.workspace.vo.*;
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.Parameter;
import io.swagger.v3.oas.annotations.Parameters;
import io.swagger.v3.oas.annotations.enums.ParameterIn;
import io.swagger.v3.oas.annotations.media.Schema;
import io.swagger.v3.oas.annotations.tags.Tag;
import jakarta.annotation.Resource;
import jakarta.validation.Valid;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;
import java.util.Map;

@Slf4j
@RestController
@Tag(name = "SpaceNode")
@ApiResource(path = "/node")
public class SpaceNodeController {

    @Resource
    private SpaceNodeQueryManager spaceNodeQueryManager;

    @Resource
    private SpaceNodeUpdateManager spaceNodeUpdateManager;

    @Resource
    private INodeService nodeService;

    @Resource
    private PermissionChecker permissionChecker;

    @Resource
    private SpaceNodeImportTaskQueryManager spaceNodeImportTaskQueryManager;

    @Resource
    private SpaceNodeImportTaskUpdateManager spaceNodeImportTaskUpdateManager;

    @Resource
    private ICollabspaceGrpcClientService collabspaceGrpcClientService;

    @PostResource(path = "/createSpaceNode", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Create Space Node")
    public ResponseData<TreeNode<SpaceNodeVo>> createSpaceNode(@RequestBody @Valid SpaceNodeCreateRo ro) {
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        // 鉴权
        if (ro.getParentId() == null ||  ro.getParentId() == 0) {
            // 创建在根节点, 取space默认权限
            permissionChecker.requireUser(userId).onSpaceDefaultNode(spaceId).needPermission(NodePermission.CREATE_NODE);
        } else {
            // 在已有节点下创建, 取父节点权限
            NodeEntity nodeEntity = nodeService.getById(ro.getParentId());
            if (nodeEntity == null) {
                throw new BusinessException(SpaceNodeException.NOT_EXIST);
            }
            permissionChecker.requireUser(userId).onNode(nodeEntity.getRelId()).needPermission(NodePermission.CREATE_NODE);
        }

        TreeNode<SpaceNodeVo> result = spaceNodeUpdateManager.createSpaceNode(spaceId, userId, ro);
        return ResponseData.success(result);
    }

    @PostResource(path = "/importSpaceNode", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Import Space Node")
    public ResponseData<TreeNode<SpaceNodeVo>> importSpaceNode(@RequestBody @Valid SpaceNodeImportRo ro) {
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        // 鉴权
        if (ro.getParentId() == null ||  ro.getParentId() == 0) {
            // 创建在根节点, 取space默认权限
            permissionChecker.requireUser(userId).onSpaceDefaultNode(spaceId).needPermission(NodePermission.CREATE_NODE);
        } else {
            // 在已有节点下创建, 取父节点权限
            NodeEntity nodeEntity = nodeService.getById(ro.getParentId());
            if (nodeEntity == null) {
                throw new BusinessException(SpaceNodeException.NOT_EXIST);
            }
            permissionChecker.requireUser(userId).onNode(nodeEntity.getRelId()).needPermission(NodePermission.CREATE_NODE);
        }
        TreeNode<SpaceNodeVo> result = spaceNodeUpdateManager.importSpaceNode(spaceId, userId, ro);
        return ResponseData.success(result);
    }

    @PostResource(path = "/registerImportTree", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Register Import Tree")
    public ResponseData<RegisterImportVo> registerImportTree(@RequestBody @Valid RegisterImportRo ro) {
        String spaceId = SpaceHolder.get();
        Long userId = SessionContext.getUserId();
        if (ro.getTargetParentId() == null ||  ro.getTargetParentId() == 0) {
            // 创建在根节点, 取space默认权限
            permissionChecker.requireUser(userId).onSpaceDefaultNode(spaceId).needPermission(NodePermission.CREATE_NODE);
        } else {
            // 在已有节点下创建, 取父节点权限
            NodeEntity nodeEntity = nodeService.getById(ro.getTargetParentId());
            if (nodeEntity == null) {
                throw new BusinessException(SpaceNodeException.NOT_EXIST);
            }
            permissionChecker.requireUser(userId).onNode(nodeEntity.getRelId()).needPermission(NodePermission.CREATE_NODE);
        }
        RegisterImportVo vo = spaceNodeImportTaskUpdateManager.registerImportTree(spaceId, ro);
        return ResponseData.success(vo);
    }

    @PostResource(path = "/commitImport", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Commit Import (batch)")
    public ResponseData<ImportTaskVo> commitImport(@RequestBody @Valid CommitImportRo ro) {
        ImportTaskVo vo = spaceNodeImportTaskUpdateManager.commitImport(ro.getTaskId(), ro.getItems());
        return ResponseData.success(vo);
    }

    @PostResource(path = "/completeImport", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Complete Import")
    public ResponseData<Void> completeImport(@RequestBody @Valid CompleteImportRo ro) {
        spaceNodeImportTaskUpdateManager.completeImport(ro.getTaskId());
        return ResponseData.success();
    }

    @GetResource(path = "/import/{taskId}/getTaskStatus", externalOnly = true, requiredPermission = false)
    @Operation(summary = "Get Import Task Status")
    public ResponseData<ImportTaskVo> getImportTaskStatus(@PathVariable("taskId") String taskId) {
        ImportTaskVo vo = spaceNodeImportTaskQueryManager.getImportTaskStatus(taskId);
        return ResponseData.success(vo);
    }

    @GetResource(path = "/getLastImportStatus", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Get Last Import Status")
    public ResponseData<ImportTaskVo> getLastImportStatus() {
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        ImportTaskVo vo = spaceNodeImportTaskQueryManager.getImportStatusByUserIdAndSpaceId(userId, spaceId);
        return ResponseData.success(vo);
    }


    @PostResource(path = "/updateSpaceNode", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Update Space Node")
    public ResponseData<SpaceNodeVo> updateSpaceNode(@RequestBody @Valid SpaceNodeUpdateRo ro) throws JsonProcessingException {
        Long userId = SessionContext.getUserId();
        permissionChecker.requireUser(userId).onNode(ro.getId()).needPermission(NodePermission.RENAME_NODE);
        SpaceNodeVo result = spaceNodeUpdateManager.updateSpaceNode(ro,userId);
        return ResponseData.success(result);
    }

    @GetResource(path = "/spaceNodeTree")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Get Space Node Tree")
    public ResponseData<List<TreeNode<SpaceNodeVo>>> getSpaceNodeTree() {
        String spaceId = SpaceHolder.get();
        List<TreeNode<SpaceNodeVo>> result = spaceNodeQueryManager.getSpaceNodeTree(spaceId);
        return ResponseData.success(result);
    }

    @GetResource(path = "/{id}/spaceNodeInfo", requiredPermission = false)
    @Operation(summary = "Get Single Space Node Info")
    public ResponseData<TreeNode<SpaceNodeVo>> getSpaceNodeInfo(@PathVariable Long id) {
        TreeNode<SpaceNodeVo> node = spaceNodeQueryManager.getSpaceNodeById(id);
        return ResponseData.success(node);
    }

    @GetResource(path = "/app/{appSpaceNodeId}/spaceNodeInfo", requiredPermission = false, requiredLogin = false)
    @Operation(summary = "Get Single Space Node Info By AppSpaceNodeId")
    public ResponseData<SpaceNodeVo> getSpaceNodeInfoByAppSpaceNodeId(@PathVariable String appSpaceNodeId) {
        SpaceNodeVo vo = spaceNodeQueryManager.getSpaceNodeByAppId(appSpaceNodeId);
        return ResponseData.success(vo);
    }

    @PostResource(path = "/moveSpaceNode", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Move Space Node")
    public ResponseData<TreeNode<SpaceNodeVo>> moveSpaceNode(@RequestBody @Valid MoveSpaceNodeRo ro) {
        String spaceId = SpaceHolder.get();
        Long userId = SessionContext.getUserId();
//        controlTemplate.mustHaveSpaceRole(SpaceNode.MANAGER, userId, spaceId);
        TreeNode<SpaceNodeVo> result = spaceNodeUpdateManager.moveSpaceNode(spaceId, ro);
        return ResponseData.success(result);
    }

    @GetResource(path = "/{id}/deleteSpaceNode", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Delete Space Node")
    public ResponseData<Void> deleteSpaceNode(@PathVariable Long id) {
        Long userId = SessionContext.getUserId();
        permissionChecker.requireUser(userId).onNode(id).needPermission(NodePermission.REMOVE_NODE);
        spaceNodeUpdateManager.deleteSpaceNode(id,userId);
        return ResponseData.success();
    }

    @PostResource(path = "/relAppSpaceNode")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Rel App Space Node")
    public ResponseData<TreeNode<SpaceNodeVo>> relAppSpaceNode(@RequestBody @Valid AppSpaceNodeRelRo ro) {
        Long userId = SessionContext.getUserId();
        String spaceId = SpaceHolder.get();
        // 鉴权
        if (ro.getParentId() == null ||  ro.getParentId() == 0) {
            // 创建在根节点, 取space默认权限
            permissionChecker.requireUser(userId).onSpaceDefaultNode(spaceId).needPermission(NodePermission.CREATE_NODE);
        } else {
            // 在已有节点下创建, 取父节点权限
            NodeEntity nodeEntity = nodeService.getById(ro.getParentId());
            if (nodeEntity == null) {
                throw new BusinessException(SpaceNodeException.NOT_EXIST);
            }
            permissionChecker.requireUser(userId).onNode(nodeEntity.getRelId()).needPermission(NodePermission.CREATE_NODE);
        }
        TreeNode<SpaceNodeVo> result = spaceNodeUpdateManager.relAppSpaceNode(spaceId, ro, userId);
        return ResponseData.success(result);
    }

    @PostResource(path = "/filterSpaceNode")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Filter Space Node")
    public ResponseData<List<SpaceNodeFilterVo>> filterSpaceNode(@RequestBody @Valid SpaceNodeFilterRo ro)  {
        String spaceId = SpaceHolder.get();
        Long userId = SessionContext.getUserId();
        List<SpaceNodeFilterVo> result = spaceNodeQueryManager.filterSpaceNode(spaceId, userId, ro);
        return ResponseData.success(result);
    }

    @PostResource(path = "/setSpaceNodeIcon")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "set space node icon")
    public ResponseData<Void> setSpaceNodeIcon(@RequestBody @Valid SpaceNodeIconRo ro){
        spaceNodeUpdateManager.setSpaceNodeIcon(ro);
        return ResponseData.success();

    }

    @PostResource(path = "/batchMoveSpaceNode", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Batch Move Space Nodes")
    public ResponseData<Void> batchMoveSpaceNode(@RequestBody @Valid BatchMoveSpaceNodeRo ro) {
        String spaceId = SpaceHolder.get();
        spaceNodeUpdateManager.batchMoveSpaceNode(spaceId, ro);
        return ResponseData.success();
    }


    @GetResource(path = "/listDup", requiredLogin = false,requiredPermission = false)
    public ResponseData<Map<String, Map<String, List<DataCheckService.Row>>>> listDup() {
        Map<String, Map<String, List<DataCheckService.Row>>> result = spaceNodeQueryManager.listDup();
        return ResponseData.success(result);
    }

    @PostResource(path = "/updateSpaceNodeAIEnable")
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Update Space Node AI Enable Config")
    public ResponseData<SpaceNodeVo> updateSpaceNodeAIEnable(@RequestBody @Valid SpaceNodeAIEnableUpdateRo ro) throws JsonProcessingException {
        Long userId = SessionContext.getUserId();
        permissionChecker.requireUser(userId).onNode(ro.getId()).needPermission(NodePermission.AI_ENABLE);
        SpaceNodeVo result = spaceNodeUpdateManager.updateSpaceNodeAIEnable(ro);
        return ResponseData.success(result);
    }

    @PostResource(path = "/updateSpaceNodeAIQuotedBatch", requiredLogin = false,requiredPermission = false)
    @Operation(summary = "Batch Update Space Node AI Quoted")
    public ResponseData<Void> updateSpaceNodeAIQuotedBatch(@RequestBody @Valid SpaceNodeAIQuotedBatchUpdateRo ro) throws JsonProcessingException {
        spaceNodeUpdateManager.updateSpaceNodeAIQuotedBatch(ro);
        return ResponseData.success();
    }

    @PostResource(path = "/batchUpdateAICitation", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Batch Update Document AI Citation")
    public ResponseData<Void> batchUpdateAICitation(@RequestBody @Valid BatchUpdateAICitationRo ro) {
        Long userId = SessionContext.getUserId();
        if (!ro.getNodeIds().isEmpty()) {
            // AI 引用批量设置（仅文档）：这里沿用“节点维度”的 AI_ENABLE 权限做鉴权。
            // 说明：
            // - 当前仅对列表中的第一个节点做权限校验；后续批量节点的权限与空间隔离由 updateManager 内部的存在性/类型校验兜底。
            // - 若未来需要更严格的权限模型（例如每个节点分别校验/或校验同一父目录权限），应在此处扩展。
            permissionChecker.requireUser(userId).onNode(ro.getNodeIds().getFirst()).needPermission(NodePermission.AI_ENABLE);
        }
        // 进入业务链路：逐个节点校验（存在/类型）+ 父级文件夹策略覆盖判断（覆盖则返回 610）+ 更新 aiEnable 字段
        spaceNodeUpdateManager.batchUpdateAICitation(ro);
        return ResponseData.success();
    }

    @PostResource(path = "/{id}/aiCitation", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Update Single Document AI Citation")
    public ResponseData<SpaceNodeVo> updateAICitation(@PathVariable("id") Long id, @RequestBody @Valid UpdateAICitationRo ro) {
        Long userId = SessionContext.getUserId();
        permissionChecker.requireUser(userId).onNode(id).needPermission(NodePermission.AI_ENABLE);
        SpaceNodeVo result = spaceNodeUpdateManager.updateAICitation(id, ro);
        return ResponseData.success(result);
    }

    @GetResource(path = "/{id}/aiReferenceStatus", requiredPermission = false)
    @Operation(summary = "Get AI Reference Status")
    public ResponseData<AiReferenceStatusVo> getAiReferenceStatus(@PathVariable("id") Long id) {
        AiReferenceStatusVo vo = spaceNodeQueryManager.getAiReferenceStatus(id);
        return ResponseData.success(vo);
    }

    @PostResource(path = "/{id}/aiReferenceStatus", externalOnly = true)
    @Parameters({
            @Parameter(name = ParamsConstants.SPACE_ID, description = "space id", required = true,
                    schema = @Schema(type = "string"), in = ParameterIn.HEADER, example = "spcVyED5StRev"),
    })
    @Operation(summary = "Update Folder AI Reference Status")
    public ResponseData<SpaceNodeVo> updateFolderAIReferenceStatus(@PathVariable("id") Long id, @RequestBody @Valid UpdateFolderAIReferenceStatusRo ro) {
        Long userId = SessionContext.getUserId();
        permissionChecker.requireUser(userId).onNode(id).needPermission(NodePermission.AI_ENABLE);
        SpaceNodeVo result = spaceNodeUpdateManager.updateFolderAIReferenceStatus(id, ro);
        return ResponseData.success(result);
    }

    @GetResource(path = "/listManagedSpaceDataSheet", requiredPermission = false)
    @Operation(summary = "List Managed Space DataSheet")
    public ResponseData<List<SpaceWithNodeVo>> listManagedSpaceDataSheet() {
        Long userId = SessionContext.getUserId();
        List<SpaceWithNodeVo> spaceWithNodeVos = spaceNodeQueryManager.listManagedSpaceDataSheet(userId);
        return ResponseData.success(spaceWithNodeVos);
    }

    @GetResource(path = "/listManagedSpaceDataSheetMirror", requiredPermission = false)
    @Operation(summary = "List Managed Space DataSheet")
    public ResponseData<List<SpaceWithNodeVo>> listManagedSpaceDataSheetMirror() {
        Long userId = SessionContext.getUserId();
        //grpc
        List<SpaceWithNodeVo> spaceWithNodeVos = collabspaceGrpcClientService.listManagedSpaceDataSheetMirror(userId);
        return ResponseData.success(spaceWithNodeVos);
    }

}

