    @JsonSerialize(nullsUsing = NullCollectionSerializer.class)
    @Schema(description = "Child Nodes")
    private List<SpaceNodeTreeNodeVo> children;

    public static SpaceNodeTreeNodeVo from(TreeNode<SpaceNodeVo> node) {
        if (node == null) {
            return null;
        }
        SpaceNodeTreeNodeVo vo = new SpaceNodeTreeNodeVo();
